const mundial2026Questions = [

  // ── EL TORNEO 2026 ───────────────────────────────────────────
  {t:"m",q:"¿Cuántos países co-organizan el Mundial 2026, siendo la primera vez en la historia que son tres?",o:["2 países","3 países","4 países","Solo 1 país"],a:1,exp:"Estados Unidos, Canadá y México son los tres países co-anfitriones del Mundial 2026, la primera vez en la historia que tres naciones comparten una Copa del Mundo.",extra:"La candidatura conjunta fue presentada en 2017 y seleccionada en junio de 2018 durante el Congreso de la FIFA en Moscú. Competía contra la candidatura de Marruecos."},
  {t:"m",q:"¿Cuántos equipos participarán en el Mundial 2026, un 50% más que en ediciones anteriores de 32 equipos?",o:["40 equipos","44 equipos","48 equipos","56 equipos"],a:2,exp:"El Mundial 2026 tendrá 48 selecciones, el mayor número en la historia del torneo. Significa un salto de 16 equipos respecto al formato de 32 que rigió desde 1998.",extra:"El aumento busca dar más representación a África, Asia y CONCACAF. Implica más partidos pero también más cuidado en la calidad del torneo."},
  {t:"m",q:"¿En qué estadio se jugará la final del Mundial 2026?",o:["Rose Bowl (Los Ángeles)","AT&T Stadium (Dallas)","MetLife Stadium (Nueva York/Nueva Jersey)","Hard Rock Stadium (Miami)"],a:2,exp:"La final del Mundial 2026 se disputará en el MetLife Stadium, ubicado en East Rutherford, Nueva Jersey, en el área metropolitana de Nueva York.",extra:"El MetLife Stadium tiene capacidad para más de 82.500 espectadores. Es el hogar de los NY Giants y NY Jets de la NFL, adaptado para el fútbol."},
  {t:"m",q:"¿Cuántos partidos se disputarán en total en el Mundial 2026?",o:["64 partidos","80 partidos","104 partidos","96 partidos"],a:2,exp:"El Mundial 2026 tendrá 104 partidos, comparado con los 64 de ediciones de 32 equipos. Es un aumento significativo del 62% en número de partidos.",extra:"Los 104 partidos se distribuyen en fase de grupos (96 partidos de grupos), ronda de 16, cuartos, semifinales, partido por el tercer puesto y final."},
  {t:"m",q:"¿Cuántas ciudades sede tendrá el Mundial 2026 entre los tres países anfitriones?",o:["12 ciudades","14 ciudades","16 ciudades","20 ciudades"],a:2,exp:"El Mundial 2026 tendrá 16 ciudades sede: 11 en Estados Unidos, 2 en Canadá (Vancouver y Toronto) y 3 en México (Ciudad de México, Guadalajara y Monterrey).",extra:"Nunca antes un Mundial tuvo tantas ciudades sede. Los viajes entre países harán del 2026 un torneo logísticamente único en la historia del fútbol."},
  {t:"m",q:"¿Cuántas ciudades aporta México como sede del Mundial 2026?",o:["1 ciudad","2 ciudades","3 ciudades","4 ciudades"],a:2,exp:"México aporta tres ciudades: Ciudad de México (Estadio Azteca), Guadalajara (Estadio Akron) y Monterrey (Estadio BBVA).",extra:"México ya organizó los Mundiales de 1970 y 1986. La participación en 2026 lo convertirá en el único país que habrá co-organizado o albergado tres Mundiales masculinos."},
  {t:"m",q:"¿Cuántas ciudades aporta Canadá como sede del Mundial 2026?",o:["1 ciudad","2 ciudades","3 ciudades","4 ciudades"],a:1,exp:"Canadá aporta dos ciudades sede: Vancouver (BC Place) y Toronto (BMO Field), siendo la primera vez que Canadá alberga un Mundial masculino.",extra:"BC Place en Vancouver tiene capacidad para 54.500 espectadores. Para el Mundial se instalará césped natural temporal. Canadá sí organizó el Mundial Femenino en 2015."},
  {t:"f",q:"El partido inaugural del Mundial 2026 se jugará en el Estadio Azteca de la Ciudad de México.",o:["Verdadero","Falso"],a:0,exp:"Verdadero. El partido inaugural del Mundial 2026 está programado para el 11 de junio de 2026 en el Estadio Azteca, como reconocimiento al rol histórico de México.",extra:"Este detalle fue parte de las negociaciones de la candidatura. El Azteca inaugurando el torneo es un guiño al papel clave de México en la historia del fútbol mundial."},
  {t:"m",q:"¿Cuándo comenzará el Mundial 2026 y cuándo se jugará la final?",o:["1 junio - 10 julio","11 junio - 19 julio","15 mayo - 30 junio","20 junio - 25 julio"],a:1,exp:"El Mundial 2026 transcurrirá del 11 de junio al 19 de julio, con 39 días de competición entre los tres países anfitriones.",extra:"La duración de 39 días es similar a ediciones anteriores de 32 equipos. Con 48 equipos y 104 partidos, el calendario es ajustado pero manejable."},
  {t:"m",q:"¿Cuál es el nuevo formato de la fase de grupos del Mundial 2026?",o:["8 grupos de 6 equipos","12 grupos de 4 equipos","6 grupos de 8 equipos","10 grupos de 4 equipos y 2 de 4"],a:1,exp:"El Mundial 2026 tiene 12 grupos de 4 equipos. Los dos primeros de cada grupo y los 8 mejores terceros clasificados avanzan a una ronda de 32 equipos (octavos de final).",extra:"El formato de 'los mejores terceros' es similar al usado en el Mundial de 24 equipos (1982-1994). Genera expectativa hasta el final de la fase de grupos."},
  {t:"f",q:"Los tres países anfitriones (Estados Unidos, Canadá y México) clasifican automáticamente al Mundial 2026 sin necesidad de pasar por eliminatorias.",o:["Verdadero","Falso"],a:0,exp:"Verdadero. Como es tradición, los países anfitriones clasifican directamente. Sus tres plazas son adicionales a los cupos regulares de clasificación.",extra:"Para CONCACAF esto es especialmente ventajoso: los tres anfitriones más los clasificados en eliminatorias suman hasta 6 cupos totales para la región."},

  // ── EL AZTECA: EL ESTADIO HISTÓRICO ──────────────────────────
  {t:"m",q:"¿En cuántas Copas del Mundo habrá albergado partidos el Estadio Azteca si se cuenta el 2026?",o:["2 Mundiales","3 Mundiales","4 Mundiales","5 Mundiales"],a:1,exp:"El Estadio Azteca albergó el Mundial de 1970, el de 1986 y ahora el de 2026. Será el único estadio en la historia en haber recibido partidos de tres Copas del Mundo diferentes.",extra:"En 1970 fue sede de la final (Brasil 4-1 Italia). En 1986 fue sede de la final (Argentina 3-2 Alemania) y del histórico 'gol del siglo' de Maradona."},
  {t:"m",q:"¿Qué partido histórico de Diego Maradona se jugó en el Estadio Azteca en el Mundial 1986?",o:["La final contra Alemania","El gol del siglo y la Mano de Dios contra Inglaterra","El hattrick a Bélgica","El debut de Argentina"],a:1,exp:"El 22 de junio de 1986 en el Azteca, Maradona marcó dos de los goles más famosos de la historia: la 'Mano de Dios' y el 'Gol del Siglo' ante Inglaterra.",extra:"El Azteca fue así testigo de ambos extremos del genio maradoniano: la trampa y la obra de arte, en el mismo partido. Argentina ganó 2-1."},

  // ── HISTORIA GENERAL DEL MUNDIAL ─────────────────────────────
  {t:"m",q:"¿En qué año se disputó el primer Mundial de fútbol y qué país fue sede?",o:["1926 en Italia","1928 en Argentina","1930 en Uruguay","1932 en Brasil"],a:2,exp:"La primera Copa Mundial de la FIFA se jugó en Uruguay en 1930, con 13 selecciones participantes. Uruguay ganó el torneo como local.",extra:"Uruguay fue elegida sede en parte como homenaje a sus dos títulos olímpicos (1924 y 1928). El viaje en barco de las selecciones europeas duraba semanas."},
  {t:"m",q:"¿Cuántas selecciones participaron en el primer Mundial de 1930 en Uruguay?",o:["8 selecciones","13 selecciones","16 selecciones","24 selecciones"],a:1,exp:"Solo 13 selecciones participaron en Uruguay 1930: 9 de América (incluyendo el anfitrión) y solo 4 europeas que aceptaron el largo viaje en barco.",extra:"La mayoría de los equipos europeos se negó a participar por el costo y duración del viaje. Bélgica, Francia, Yugoslavia y Rumanía fueron las cuatro que viajaron."},
  {t:"m",q:"¿Qué país es el único que ha participado en TODOS los Mundiales de la historia desde 1930?",o:["Alemania","Argentina","Italia","Brasil"],a:3,exp:"Brasil es el único país que ha estado presente en los 22 Mundiales disputados hasta 2022, sin haberse perdido ninguna edición.",extra:"Brasil también es el país con más títulos mundiales (5). Su clasificación automática en todas las ediciones refleja la fortaleza histórica del fútbol brasileño."},
  {t:"m",q:"¿Cuántos títulos mundiales tiene Brasil, el país más ganador?",o:["3 títulos","4 títulos","5 títulos","6 títulos"],a:2,exp:"Brasil ganó 5 Copas del Mundo: 1958 (Suecia), 1962 (Chile), 1970 (México), 1994 (USA) y 2002 (Japón/Corea del Sur).",extra:"En 1970, al ganar por tercera vez, Brasil se quedó con la Copa Jules Rimet de forma permanente. El nuevo trofeo se estrenó en 1974."},
  {t:"m",q:"¿Cuántos títulos mundiales tienen Alemania e Italia respectivamente?",o:["3 y 3","4 y 4","4 y 3","3 y 4"],a:1,exp:"Tanto Alemania como Italia tienen 4 títulos mundiales cada una. Alemania ganó en 1954, 1974, 1990 y 2014; Italia en 1934, 1938, 1982 y 2006.",extra:"Ambas naciones son las únicas junto a Brasil y Argentina en haber ganado el Mundial más de dos veces. Francia y Uruguay tienen 2 cada una."},
  {t:"m",q:"¿Cuántos títulos mundiales tiene Argentina?",o:["1 título","2 títulos","3 títulos","4 títulos"],a:2,exp:"Argentina ganó la Copa del Mundo en 1978 (local), 1986 (México) y 2022 (Qatar), siendo el tercer país con más títulos.",extra:"El título de 2022 cerró el ciclo de Lionel Messi, quien finalmente obtuvo el único título que le faltaba en su carrera, superando 36 años de espera."},
  {t:"m",q:"¿Cuál es el máximo goleador en la historia de los Mundiales con 16 tantos?",o:["Ronaldo Nazário","Pelé","Just Fontaine","Miroslav Klose"],a:3,exp:"Miroslav Klose (Alemania) es el máximo goleador de la historia mundialista con 16 goles repartidos en 4 torneos: 2002 (5), 2006 (5), 2010 (4) y 2014 (2).",extra:"Klose superó el récord de Ronaldo Nazário (15 goles) al marcar en la semifinal ante Brasil en 2014. Su récord podría ser amenazado por Messi o Mbappé."},
  {t:"m",q:"¿Cuál es el gol más rápido en la historia de los Mundiales?",o:["Gol de Pelé en 1958 (45s)","Gol de Hakan Şükür en 2002 (~11s)","Gol de Maradona en 1986 (30s)","Gol de Geoff Hurst en 1966 (1 min)"],a:1,exp:"Hakan Şükür (Turquía) marcó el gol más rápido de la historia del Mundial a los 10.89 segundos del comienzo del partido ante Corea del Sur en el tercer puesto de 2002.",extra:"Turquía terminó ganando 3-2 ese partido y se quedó con el tercer puesto. El gol de Şükür es uno de los récords más difíciles de batir del fútbol mundial."},
  {t:"m",q:"¿Cuál es la mayor goleada de la historia de los Mundiales?",o:["Brasil 8-3 Polonia (1938)","Suecia 8-0 Cuba (1938)","Hungría 10-1 El Salvador (1982)","Alemania 8-0 Arabia Saudita (2002)"],a:2,exp:"Hungría 10 - El Salvador 1 en el Mundial de España 1982 es la mayor goleada de la historia. Laszlo Kiss fue el gran protagonista con un hat-trick en solo 7 minutos.",extra:"El Equipo de El Salvador estaba en su único Mundial. A pesar de la goleada, los jugadores salvadoreños son recordados por su coraje al terminar el partido."},
  {t:"m",q:"¿Qué jugador tiene el récord de más partidos disputados en Mundiales con 25 apariciones?",o:["Paolo Maldini","Cafu","Lothar Matthäus","Diego Maradona"],a:2,exp:"Lothar Matthäus (Alemania) jugó 25 partidos en Mundiales a lo largo de 5 ediciones (1982, 1986, 1990, 1994 y 1998), un récord de longevidad.",extra:"Matthäus participó en 5 Mundiales diferentes, ganando en 1990. Su último torneo fue a los 37 años. Es además uno de los mejores centrocampistas de la historia."},
  {t:"m",q:"¿Cuál es el jugador más joven en marcar un gol en la historia de los Mundiales?",o:["Cesc Fàbregas","Michael Owen","Kylian Mbappé","Pelé"],a:3,exp:"Pelé marcó su primer gol mundialista el 19 de junio de 1958 ante Gales, a los 17 años y 239 días, convirtiéndose en el goleador más joven de la historia.",extra:"Ese gol de Pelé fue el único del partido (Brasil 1-0 Gales) y lo catapultó al estrellato mundial. Brasil ganó ese torneo con Pelé como figura revelación."},
  {t:"m",q:"¿Cuántos Mundiales ganó Pelé a lo largo de su carrera?",o:["1 Mundial","2 Mundiales","3 Mundiales","4 Mundiales"],a:2,exp:"Pelé ganó 3 Copas del Mundo con Brasil: 1958 (Suecia, con 17 años), 1962 (Chile, lesionado tras el primer partido) y 1970 (México, en su mejor nivel).",extra:"El de 1970 se considera el de su mejor actuación. El equipo de 1970 con Pelé, Rivelino, Jairzinho y Tostao es considerado uno de los mejores de la historia."},
  {t:"f",q:"Brasil es el único país que ganó el Mundial en su propio territorio como local.",o:["Verdadero","Falso"],a:1,exp:"Falso. Uruguay (1930), Italia (1934), Inglaterra (1966), Alemania (1974), Argentina (1978) y Francia (1998) ganaron el Mundial siendo locales. Brasil NUNCA ganó siendo sede.",extra:"Brasil perdió ante Uruguay 2-1 en 1950 (Maracanazo) siendo local y fue eliminado por Alemania 7-1 en 2014. El título como local se le sigue escapando."},

  // ── RECORDS Y CURIOSIDADES HISTÓRICAS ────────────────────────
  {t:"m",q:"¿Cómo se llama el partido de 1950 donde Uruguay venció 2-1 a Brasil en el Maracaná y se coronó campeón del mundo?",o:["El Uruguayazo","El Maracanazo","El Gol Fantasma","La Tragedia de Río"],a:1,exp:"El 'Maracanazo' fue el partido del 16 de julio de 1950 en el Estadio Maracaná donde Uruguay venció a Brasil y fue campeón, ante más de 170.000 hinchas locales.",extra:"Alcides Ghiggia marcó el gol decisivo a los 79 minutos. Se cuenta que el Maracaná quedó en silencio absoluto. Ghiggia dijo: 'Solo tres personas silenciaron el Maracaná: Frank Sinatra, el Papa y yo'."},
  {t:"m",q:"¿Cómo se llama la aplastante derrota de Brasil 1-7 ante Alemania en las semifinales del Mundial 2014?",o:["El Brasileñazo","El Mineirazo","La Catástrofe de Belo Horizonte","El Siete de la Vergüenza"],a:1,exp:"El 'Mineirazo' fue el 8 de julio de 2014 en el Estadio Mineirão: Alemania goleó 7-1 a Brasil en la semifinal, la mayor derrota en la historia reciente del fútbol brasileño.",extra:"4 de los 7 goles de Alemania cayeron en solo 6 minutos (entre los minutos 23 y 29). Miroslav Klose marcó el gol 16 de su carrera mundialista ese partido."},
  {t:"m",q:"¿Qué Argentina vs Inglaterra protagonizó la 'Mano de Dios' y el 'Gol del Siglo' de Diego Maradona?",o:["Mundial España 1982","Mundial México 1986, cuartos de final","Mundial Italia 1990","Copa América 1987"],a:1,exp:"Fue el 22 de junio de 1986 en cuartos de final del Mundial de México. Maradona primero anotó con la mano y luego dribló a medio equipo inglés en el mismo partido.",extra:"Argentina ganó 2-1. El partido tenía contexto político por la Guerra de las Malvinas (1982). Maradona reconoció la Mano de Dios años después, aunque en el momento lo negó."},
  {t:"m",q:"¿Quién fue el célebre relator que describió el gol del siglo de Maradona con la frase 'Barrilete cósmico, ¿de qué planeta viniste?'?",o:["José María Múñoz","Víctor Hugo Morales","Marcelo Araujo","Alejandro Fantino"],a:1,exp:"Víctor Hugo Morales, relator uruguayo, hizo la icónica narración del gol del siglo de Maradona ante Inglaterra en el Mundial 1986, terminando con '¡Barrilete cósmico!',",extra:"La narración de Víctor Hugo Morales es considerada una de las más emotivas de la historia del deporte. El texto completo es estudiado en escuelas de periodismo deportivo."},
  {t:"m",q:"¿En qué año se usó el VAR (árbitro asistente de video) por primera vez en la Copa del Mundo?",o:["Brasil 2014","Rusia 2016","Rusia 2018","Qatar 2022"],a:2,exp:"El VAR fue implementado por primera vez en un Mundial en Rusia 2018, cambiando la forma de arbitrar y generando debates sobre si mejora o ralentiza el fútbol.",extra:"Francia vs Australia fue el primer partido donde el VAR cambió un resultado en un Mundial. Antoine Griezmann convirtió el penal revisado, Francia ganó 2-1."},
  {t:"m",q:"¿En qué Mundial Qatar 2022 un hecho inédito ocurrió con el equipo anfitrión?",o:["El anfitrión ganó el torneo","El anfitrión llegó a la final","Qatar fue el primer anfitrión eliminado en la fase de grupos","El anfitrión rechazó el trofeo"],a:2,exp:"Qatar 2022 fue el primer caso en la historia donde el equipo anfitrión fue eliminado en la fase de grupos, sin ganar ningún partido.",extra:"Qatar perdió ante Ecuador (0-2), Senegal (1-3) y empató con Países Bajos (1-1) en reclasificación. Fue un debut mundialista histórico pero muy duro para la selección catarí."},
  {t:"m",q:"¿Qué jugador ganó el Balón de Oro al mejor jugador del Mundial de Qatar 2022?",o:["Kylian Mbappé","Luka Modrić","Lionel Messi","Julián Álvarez"],a:2,exp:"Lionel Messi ganó el Balón de Oro de Qatar 2022, su segundo (ya lo había ganado en Argentina 2014). Fue el premio que coronó su desempeño en la final ante Francia.",extra:"Messi marcó 7 goles y dio 3 asistencias en el torneo. La final ante Francia (3-3 en el tiempo extra) se considera una de las mejores de la historia mundialista."},
  {t:"m",q:"¿Quién fue el máximo goleador (Bota de Oro) del Mundial de Qatar 2022 con 8 goles?",o:["Lionel Messi","Olivier Giroud","Kylian Mbappé","Julián Álvarez"],a:2,exp:"Kylian Mbappé terminó como máximo goleador de Qatar 2022 con 8 goles, incluyendo un hat-trick en la final ante Argentina. A pesar de eso, Francia perdió por penales.",extra:"El hat-trick de Mbappé en una final mundialista es solo el segundo de la historia (el primero fue de Geoff Hurst para Inglaterra en 1966 contra Alemania Occidental)."},
  {t:"m",q:"¿Cómo terminó la final del Mundial de Qatar 2022 entre Argentina y Francia?",o:["Argentina ganó 3-1","Francia ganó 4-3","Empate 3-3, Argentina ganó 4-2 en penales","Empate 2-2, Argentina ganó por penales"],a:2,exp:"La final terminó 3-3 en el tiempo extra (2-2 en el tiempo reglamentario). Argentina ganó 4-2 en la tanda de penales para consagrarse campeón del mundo.",extra:"Fue la primera final de la historia en terminar 3-3. Mbappé marcó un hat-trick para Francia pero no alcanzó. Emiliano Martínez fue clave tapando un penal."},
  {t:"m",q:"¿Cuál fue el primer Mundial que el histórico Lionel Messi ganó?",o:["Alemania 2006","Sudáfrica 2010","Brasil 2014","Qatar 2022"],a:3,exp:"Qatar 2022 fue el primer y único Mundial que Messi ganó. Luego de 4 torneos anteriores (2006, 2010, 2014 donde fue subcampeón, y 2018), finalmente levantó la copa.",extra:"En 2014, Messi fue finalista y ganó el Balón de Oro del torneo pese a que Argentina perdió la final 0-1 ante Alemania. En 2022 completó su legado."},

  // ── MUNDIALES LEGENDARIOS ─────────────────────────────────────
  {t:"m",q:"¿Qué partido dramático protagonizó Roberto Baggio en la final del Mundial de USA 1994?",o:["Marcó el gol del título en el último minuto","Falló el penal definitivo que le dio el título a Brasil","Fue expulsado en la prórroga","Lesionó al portero rival"],a:1,exp:"Roberto Baggio falló el último penal de la tanda ante Brasil en la final de USA 1994. La imagen del astro italiano de cabeza baja se convirtió en símbolo de la derrota.",extra:"Brasil ganó 3-2 en los penales tras un 0-0 de 120 minutos. Fue la primera final sin goles en el tiempo reglamentario de la historia de los Mundiales."},
  {t:"f",q:"La final del Mundial de USA 1994 entre Brasil e Italia terminó sin goles en los 90 minutos y la prórroga, siendo la primera final con penales.",o:["Verdadero","Falso"],a:0,exp:"Verdadero. El 0-0 de la final de 1994 fue la primera vez que una final mundialista llegaba a los penales. Brasil ganó 3-2 en la tanda.",extra:"Baggio, Massaro, Baresi y otros italianos fallaron penales. Fue uno de los partidos más tensos de la historia del fútbol. Brasil obtuvo así su cuarto título."},
  {t:"m",q:"¿En qué Mundial de 1998 Zinedine Zidane fue la gran figura con dos goles de cabeza en la final?",o:["USA 1994","Francia 1998","Corea-Japón 2002","Alemania 2006"],a:1,exp:"En la final de Francia 1998 ante Brasil, Zidane marcó dos goles de cabeza en la primera parte. Francia ganó 3-0 y se consagró campeón del mundo por primera vez.",extra:"El rendimiento de Ronaldo Nazário en esa final fue sospechoso (convulsionó horas antes). Brasil presentó a Ronaldo pero él tuvo un mal partido. Zidane fue la figura del torneo."},
  {t:"m",q:"¿En qué año ganó Francia su segunda Copa del Mundo y ante quién?",o:["2002 vs Brasil","2010 vs España","2014 vs Alemania","2018 vs Croacia"],a:3,exp:"Francia ganó su segundo título mundial en Rusia 2018, venciendo a Croacia 4-2 en la final. Kylian Mbappé marcó el gol que lo hizo el segundo adolescente en marcar en una final.",extra:"El primero en marcar en una final siendo adolescente fue Pelé en 1958. Mbappé tenía 19 años en Rusia 2018."},
  {t:"m",q:"¿Qué selección africana llegó por primera vez a las semifinales de un Mundial en Qatar 2022?",o:["Ghana","Nigeria","Senegal","Marruecos"],a:3,exp:"Marruecos se convirtió en el primer país africano en llegar a las semifinales de un Mundial, eliminando a España, Portugal y casi a Francia.",extra:"Los marroquíes eliminaron a España en octavos y a Portugal en cuartos. En semifinales cayeron ante Francia 0-2 pero el logro fue histórico para el fútbol africano."},
  {t:"m",q:"¿Qué primer equipo africano llegó a los cuartos de final de un Mundial, en Italia 1990?",o:["Nigeria","Costa de Marfil","Egipto","Camerún"],a:3,exp:"Camerún en Italia 1990 fue el primer equipo africano en alcanzar los cuartos de final de un Mundial, bajo la conducción del legendario Roger Milla.",extra:"Roger Milla tenía 38 años y salía al campo bailando junto al banderín del córner tras cada gol. Sus celebraciones se convirtieron en símbolo del Mundial de 1990."},
  {t:"m",q:"¿Cuál fue la primera selección asiática en llegar a las semifinales de un Mundial (2002)?",o:["Japón","Arabia Saudita","Iran","Corea del Sur"],a:3,exp:"Corea del Sur llegó a las semifinales del Mundial 2002 (co-organizado con Japón), eliminando a España e Italia en el camino, con gran nivel futbolístico y apoyo local.",extra:"La hazaña de Corea generó controversia por algunas decisiones arbitrales cuestionadas. Aun así, fue el mayor logro en la historia del fútbol de la región asiática."},

  // ── RÉCORDS Y DATOS DE JUGADORES ─────────────────────────────
  {t:"m",q:"¿Cuántos goles marcó Ronaldo Nazário (El Fenômeno) en el Mundial de Corea-Japón 2002?",o:["6 goles","7 goles","8 goles","9 goles"],a:2,exp:"Ronaldo Nazário marcó 8 goles en el Mundial 2002, siendo el máximo goleador del torneo. Brasil ganó el título venciendo a Alemania 2-0 en la final.",extra:"Ronaldo había tenido una misteriosa convulsión antes de la final de 1998 y fue subcampeón. En 2002 se redimió siendo la figura del torneo. Sus dos goles ante Alemania fueron épicos."},
  {t:"m",q:"¿Cuántos Mundiales jugó Diego Maradona como futbolista?",o:["2 Mundiales","3 Mundiales","4 Mundiales","5 Mundiales"],a:2,exp:"Maradona jugó 4 Mundiales como jugador: Argentina 1978 (fue al plantel pero no jugó), España 1982, México 1986 (campeón y mejor jugador) e Italia 1990.",extra:"En 1978 fue convocado pero Menotti no lo incluyó en la lista final. Fue una de las grandes controversias del fútbol argentino. Argentina ganó igual pero sin Maradona."},
  {t:"m",q:"¿Cuál fue el último Mundial de Maradona como jugador, donde Argentina llegó a la final?",o:["España 1982","México 1986","Italia 1990","USA 1994"],a:2,exp:"Italia 1990 fue el último Mundial de Maradona como jugador. Argentina llegó a la final pero cayó ante Alemania Occidental 0-1 con un penal polémico al final.",extra:"Maradona fue el capitán y figura de esa Argentina defensiva. En la final lloró en el podio. Fue su última aparición como protagonista en un Mundial."},
  {t:"m",q:"¿Cuántos Mundiales jugó Lionel Messi en total antes de ganar el título en Qatar 2022?",o:["3 Mundiales","4 Mundiales","5 Mundiales","6 Mundiales"],a:1,exp:"Messi jugó 5 Mundiales: Alemania 2006 (18 años), Sudáfrica 2010, Brasil 2014 (subcampeón), Rusia 2018 y Qatar 2022 (campeón).",extra:"En 2014 fue subcampeón y ganó el Balón de Oro del torneo (controversial elección por muchos). El 2022 fue su quinta y probablemente última Copa del Mundo."},

  // ── EL TROFEO Y LA COPA JULES RIMET ─────────────────────────
  {t:"m",q:"¿Cómo se llamaba el trofeo original de la Copa del Mundo que Brasil se quedó definitivamente tras ganarla por tercera vez?",o:["Copa Rimet","Copa Jules Rimet","El Trofeo de Oro","Copa FIFA"],a:1,exp:"La Copa Jules Rimet, llamada así por el presidente de la FIFA que impulsó el torneo, fue ganada definitivamente por Brasil al ganar su tercera Copa en 1970.",extra:"La Copa Jules Rimet era de plata dorada y representaba a Nike alada, la diosa griega de la victoria. Brasil recibió una réplica; el original fue robado en Brasil en 1983 y nunca recuperado."},
  {t:"f",q:"La Copa Jules Rimet original fue robada en Brasil en 1983 y nunca recuperada, probablemente siendo fundida.",o:["Verdadero","Falso"],a:0,exp:"Verdadero. La Copa Jules Rimet fue robada en 1983 de la sede de la Confederación Brasileña de Fútbol. Nunca se recuperó y se cree que fue fundida para vender el oro.",extra:"Paradójicamente, el trofeo ya había sido robado anteriormente en Inglaterra en 1966 (cuatro meses antes del Mundial) y fue encontrado por un perro llamado Pickles."},
  {t:"m",q:"¿De qué material está hecho el actual trofeo de la Copa Mundial de la FIFA, introducido en 1974?",o:["Plata y bronce","Oro macizo de 18 quilates con base de malaquita","Acero inoxidable dorado","Platino y cristal"],a:1,exp:"El trofeo actual, diseñado por el escultor italiano Silvio Gazzaniga, es de oro macizo de 18 quilates y pesa 6,1 kg. La base es de malaquita (piedra verde semipreciosa).",extra:"El diseño representa a dos figuras humanas sosteniendo el globo terráqueo. Solo los capitanes y jefes de delegación de los equipos que ganaron pueden tocarlo."},
  {t:"m",q:"¿En qué año se introdujo el actual trofeo de la Copa Mundial, usado por primera vez en Alemania 1974?",o:["1970","1974","1978","1982"],a:1,exp:"El nuevo trofeo de la FIFA debutó en el Mundial de Alemania Occidental 1974, donde la selección local lo levantó por primera vez. Johann Cruyff llegó a la final con Países Bajos pero no lo ganó.",extra:"El trofeo fue diseñado por el escultor Silvio Gazzaniga y seleccionado entre 53 propuestas de 7 países. Permanece sin cambios desde entonces."},

  // ── FORMATO HISTÓRICO Y EVOLUCIÓN ────────────────────────────
  {t:"m",q:"¿En qué año el Mundial pasó de 16 a 24 equipos por primera vez?",o:["1970","1978","1982","1986"],a:2,exp:"El Mundial de España 1982 fue el primero con 24 equipos, aumentando desde los 16 que participaron en todos los torneos desde 1954 hasta 1978.",extra:"Con 24 equipos se añadieron nuevos cupos para África, Asia y CONCACAF, ampliando la representación global del torneo."},
  {t:"m",q:"¿En qué año el Mundial pasó de 24 a 32 equipos?",o:["1990","1994","1998","2002"],a:2,exp:"El Mundial de Francia 1998 fue el primero con 32 equipos, formato que rigió hasta el Mundial de Qatar 2022, siendo el último de 32 selecciones.",extra:"Con 32 equipos, África pasó de 3 a 5 cupos y Asia de 2 a 4. El nuevo formato incluía 8 grupos de 4 equipos con los 2 primeros clasificados."},
  {t:"m",q:"¿Cuándo se usaron por primera vez los penales como desempate en un partido de Mundial?",o:["México 1970","Argentina 1978","España 1982","México 1986"],a:2,exp:"Los penales se usaron por primera vez en un Mundial en España 1982: Alemania Occidental venció a Francia 5-4 en penales en la semifinal, tras empatar 3-3 en la prórroga.",extra:"Esa semifinal fue un partido épico con remontadas y goles espectaculares. Los penales eran un recurso nuevo y dramático; Schumacher y su falta a Battiston marcaron el partido."},
  {t:"m",q:"¿En qué edición del Mundial se introdujeron los tarjetas amarillas y rojas como sistema de sanciones?",o:["Chile 1962","Inglaterra 1966","México 1970","Alemania 1974"],a:2,exp:"Las tarjetas amarillas y rojas se usaron por primera vez en el Mundial de México 1970, idea del árbitro inglés Ken Aston inspirada en los semáforos de tráfico.",extra:"Ken Aston tuvo la idea manejando su auto en Londres al ver un semáforo: amarillo = atención/amonestación, rojo = parar/expulsión. El sistema se adoptó inmediatamente."},
  {t:"f",q:"La regla del gol de oro (golden goal) fue usada en algunos Mundiales donde el primer gol en prórroga determinaba el ganador.",o:["Verdadero","Falso"],a:0,exp:"Verdadero. El 'gol de oro' (o sudden death) se usó en los Mundiales de 1998 y 2002 antes de ser eliminado. El primer gol en prórroga terminaba el partido.",extra:"Francia ganó la semifinal de 1998 ante Paraguay con un gol de oro de Blanc. En 2006 y posteriores se volvió al formato tradicional de dos tiempos de prórroga completos."},

  // ── PAÍSES BAJOS: LOS ETERNOS SUBCAMPEONES ───────────────────
  {t:"m",q:"¿Cuántas veces fue finalista Países Bajos (Holanda) sin ganar nunca el Mundial?",o:["2 veces","3 veces","4 veces","5 veces"],a:1,exp:"Países Bajos perdió 3 finales: 1974 (vs Alemania Occidental), 1978 (vs Argentina) y 2010 (vs España). Es el país con más finales sin ganar.",extra:"El equipo de 1974 con Cruyff y el 'Total Football' es considerado uno de los mejores en nunca ganar un Mundial. Perdieron la final 2-1 ante Alemania pese a dominar."},
  {t:"m",q:"¿Cómo se llamaba el revolucionario sistema táctico con el que Países Bajos deslumbró en los 70?",o:["Catenaccio","Tiki-taka","Total Football (Fútbol Total)","Gegenpressing"],a:2,exp:"El 'Total Football' (Totaalvoetbal) fue el sistema donde todos los jugadores podían ocupar cualquier posición, creando confusión en el rival. Johan Cruyff era su máximo exponente.",extra:"El Total Football fue desarrollado en el Ajax de los 70 y llevado a la selección holandesa. Revolucionó el fútbol y sus principios siguen vigentes en equipos modernos como el Barcelona."},

  // ── CURIOSIDADES ÚNICAS ───────────────────────────────────────
  {t:"m",q:"¿Cuántos espectadores se calcula que presenciaron el partido Uruguay vs Brasil en el Maracaná en 1950?",o:["80.000 personas","120.000 personas","Entre 170.000 y 200.000 personas","300.000 personas"],a:2,exp:"Se calcula que entre 170.000 y 200.000 personas estuvieron en el Maracaná para el partido definitorio de 1950. Es el partido con más espectadores presentes en la historia del fútbol.",extra:"El Estadio Maracaná tenía capacidad ilimitada en ese entonces (se paraba). No había registros exactos. La derrota local ante Uruguay dejó un silencio absoluto en el estadio."},
  {t:"m",q:"¿Qué portero italiano tiene el récord de más minutos invicto en Mundiales con 517 minutos?",o:["Gianluigi Buffon","Dino Zoff","Walter Zenga","Sebastiano Rossi"],a:2,exp:"Walter Zenga mantuvo su arco en cero durante 517 minutos en el Mundial de Italia 1990, un récord que aún permanece como el mayor período sin encajar en Mundiales.",extra:"Zenga encadenó 5 partidos completos sin recibir gol. El récord se terminó en el partido ante Argentina, cuando Claudio Caniggia marcó de cabeza en semifinales."},
  {t:"m",q:"¿Quién fue el primer jugador en ser expulsado en una final de la Copa del Mundo?",o:["Zinedine Zidane (2006)","Marco Mateus (2010)","Carlos Monzón (1990)","Pedro Monzón (1990)"],a:3,exp:"Pedro Monzón (Argentina) fue expulsado en la final de Italia 1990 ante Alemania, siendo el primer jugador en recibir una tarjeta roja en una final mundialista.",extra:"En esa misma final, su compatriota Gustavo Dezotti también fue expulsado. Argentina terminó con 9 jugadores y perdió 0-1 con un penal polémico al final."},
  {t:"m",q:"¿Qué famosa cabezazo de Zinedine Zidane ocurrió en la final del Mundial 2006?",o:["Marcó el gol del título","Le dio un cabezazo a Materazzi en el pecho y fue expulsado","Falló el penal definitivo","Perdió el balón que llevó al gol de Italia"],a:1,exp:"En la prórroga de la final de Alemania 2006, Zidane le dio un cabezazo a Marco Materazzi en el pecho y fue expulsado. Francia perdió los penales ante Italia 3-5.",extra:"Fue el último partido de Zidane como profesional. Materazzi supuestamente insultó a la madre o hermana de Zidane. El incidente sigue siendo uno de los más debatidos de la historia."},
  {t:"m",q:"¿Qué extraña historia rodeó a Ronaldo Nazário antes de la final de 1998 ante Francia?",o:["Fue amenazado de muerte","Sufrió una convulsión misteriosa horas antes y lo pusieron en la lista a último momento","Tuvo una lesión que lo dejó cojo","Se peleó con el DT"],a:1,exp:"Horas antes de la final, Ronaldo sufrió una convulsión misteriosa. Fue borrado de la lista inicial y luego reincorporado. Jugó pero tuvo su peor actuación; Brasil perdió 0-3.",extra:"La causa de la convulsión nunca se aclaró públicamente. Generó teorías sobre presión del patrocinador Nike, problemas médicos o nerviosos. Fue uno de los mayores misterios del fútbol."},

  // ── MUNDIALES: ANFITRIONES Y SEDES ───────────────────────────
  {t:"m",q:"¿En qué año organizó Estados Unidos su último Mundial antes del 2026?",o:["1990","1994","2002","2010"],a:1,exp:"Estados Unidos organizó el Mundial de 1994, que fue un éxito de asistencia y marketing pese a que el fútbol no era el deporte principal del país.",extra:"USA 1994 estableció el récord de promedio de asistencia por partido que duró décadas. El torneo fue clave para el crecimiento posterior de la MLS y el fútbol en Norteamérica."},
  {t:"m",q:"¿Qué países co-organizaron el Mundial de 2002, siendo la primera vez que dos naciones compartían la sede?",o:["China y Japón","Japón y Corea del Sur","Corea del Sur y Taiwán","China y Corea del Sur"],a:1,exp:"Japón y Corea del Sur fueron los primeros co-anfitriones en la historia del Mundial en 2002. El torneo tuvo 20 estadios entre los dos países.",extra:"La co-organización fue controversial al principio: ambos países querían ser los únicos anfitriones. Terminó siendo exitoso y abrió la puerta para la co-organización de 2026."},
  {t:"m",q:"¿Cuántos Mundiales organizó México antes del 2026?",o:["1 Mundial","2 Mundiales","3 Mundiales","4 Mundiales"],a:1,exp:"México organizó dos Mundiales: 1970 (donde Brasil ganó su 3er título con Pelé) y 1986 (donde Argentina con Maradona ganó su 2do título). Ahora será parte del 2026.",extra:"En 1986, México asumió la organización de urgencia reemplazando a Colombia, que renunció por problemas económicos. Tuvo solo 3 años para organizar el torneo."},
  {t:"f",q:"El Mundial 2026 será la primera vez que Canadá organiza una Copa del Mundo masculina.",o:["Verdadero","Falso"],a:0,exp:"Verdadero. Canadá nunca organizó un Mundial masculino. Sin embargo, sí organizó el Mundial Femenino en 2015 y la Copa Oro de la CONCACAF en múltiples ocasiones.",extra:"Con el 2026, Canadá también aprovechó para fortalecer su programa de fútbol. La clasificación de Canadá para el Mundial de Qatar 2022 fue el primer paso de ese crecimiento."},
  {t:"m",q:"¿Cuántas ciudades estadounidenses serán sede del Mundial 2026?",o:["8 ciudades","9 ciudades","11 ciudades","13 ciudades"],a:2,exp:"Estados Unidos aporta 11 ciudades sede al Mundial 2026: Nueva York/Nueva Jersey, Los Ángeles (dos estadios), Dallas, Miami, San Francisco, Seattle, Kansas City, Boston y Filadelfia.",extra:"El MetLife Stadium (NY/NJ) albergará la final. El Rose Bowl (LA) fue también sede del Mundial 1994. SoFi Stadium es uno de los recintos más modernos del mundo."},

  // ── DATOS DE CLASIFICACIÓN 2026 ───────────────────────────────
  {t:"m",q:"¿Cuántos cupos le corresponden a la UEFA (Europa) en el Mundial 2026?",o:["13 cupos","14 cupos","16 cupos","18 cupos"],a:2,exp:"Europa tiene 16 cupos directos en el Mundial 2026 (más plazas de repechaje), el mayor número de cualquier confederación, reflejando el nivel del fútbol europeo.",extra:"El aumento de cupos fue proporcional al total de 48 equipos. Europa pasó de 13 plazas (en el formato de 32) a 16, una ganancia de 3 cupos directos."},
  {t:"m",q:"¿Cuántos cupos le corresponden a la CONMEBOL (Sudamérica) en el Mundial 2026?",o:["4 cupos","5 cupos","6 cupos + repechaje","8 cupos"],a:2,exp:"Sudamérica tiene 6 cupos directos más uno adicional en el repechaje intercontinental para el Mundial 2026. Antes tenía 4,5 plazas.",extra:"El aumento de CONMEBOL fue muy celebrado en la región. Con 10 selecciones peleando por 6 plazas, las eliminatorias sudamericanas siguen siendo muy competitivas."},
  {t:"m",q:"¿Cuántos cupos tiene la CAF (África) en el Mundial 2026?",o:["6 cupos","8 cupos","9 cupos + repechaje","10 cupos"],a:2,exp:"África tiene 9 cupos directos más uno en el repechaje para el Mundial 2026. En el formato de 32 equipos tenía solo 5 plazas. El aumento fue muy significativo.",extra:"El crecimiento del fútbol africano justifica el aumento. Con resultados como Marruecos en Qatar 2022 (semifinalista), África demuestra cada vez más su nivel competitivo."},

  // ── CURIOSIDADES Y DATOS VARIADOS ────────────────────────────
  {t:"m",q:"¿Cuántos entrenadores argentinos ganaron la Copa del Mundo con Argentina?",o:["1 entrenador","2 entrenadores","3 entrenadores","4 entrenadores"],a:1,exp:"Dos entrenadores argentinos ganaron el Mundial: César Luis Menotti en 1978 (Argentina local) y Carlos Bilardo en 1986 (México). Lionel Scaloni sumó el tercero en 2022.",extra:"Menotti era defensor del fútbol ofensivo y bello; Bilardo del pragmático y efectivo. Sus estilos opuestos generaron un debate que dividió el fútbol argentino por décadas."},
  {t:"m",q:"¿Cómo se llama el trofeo al mejor portero de cada Copa del Mundo?",o:["Escudo de Oro","Guante de Oro","Casco de Platino","Barrera de Oro"],a:1,exp:"El Guante de Oro (Golden Glove) es el trofeo al mejor arquero del torneo. En Qatar 2022 lo ganó Emiliano Martínez (Argentina), figura clave en las semifinales y final.",extra:"El Guante de Oro se llama 'Yashin Award' en honor al legendario portero soviético Lev Yashin, considerado el mejor guardameta de la historia."},
  {t:"m",q:"¿Qué selección europea llegó a la final del Mundial 2022 pese a no clasificar directamente para el mundial anterior (2018)?",o:["Bélgica","Países Bajos","Croacia","Francia"],a:2,exp:"Croacia fue finalista en Qatar 2022 (perdió la final vs Argentina en 2018) y en 2018 también fue finalista. Croacia no tiene tradición de grandes jugadores pero sí una cultura de juego colectivo.",extra:"Luka Modrić es el cerebro de la Croacia contemporánea. En 2018 ganó el Balón de Oro del torneo a pesar de que Croacia perdió la final. En 2022 Croacia llegó al tercer puesto."},
  {t:"m",q:"¿Cuál es el partido de fútbol con más espectadores presentes en la historia?",o:["Brasil vs Argentina 1990","Brasil vs Uruguay 1950 (Maracaná)","Inglaterra vs Alemania 1966","Argentina vs Alemania 1978"],a:1,exp:"El partido Uruguay vs Brasil del 16 de julio de 1950 en el Maracaná se estima que fue presenciado por entre 170.000 y 200.000 personas, el mayor número en la historia del fútbol.",extra:"El estadio no tenía aforo oficial en esa época. Los datos varían según la fuente, pero incluso la cifra más conservadora lo convierte en el partido con más espectadores de la historia."},
  {t:"m",q:"¿Cuántos Mundiales ganó Uruguay, convirtiéndolo en uno de los países más exitosos de la historia temprana del torneo?",o:["1 Mundial","2 Mundiales","3 Mundiales","4 Mundiales"],a:1,exp:"Uruguay ganó 2 Copas del Mundo: 1930 (como local y primer campeón mundial) y 1950 (el histórico 'Maracanazo' en Brasil). Sus 2 títulos son notables para un país pequeño.",extra:"Uruguay también ganó los Juegos Olímpicos de 1924 y 1928. Para su tamaño (3,5 millones de habitantes), su palmarés internacional es único en la historia del deporte."},
  {t:"f",q:"El primer Mundial de 1930 se disputó completamente en un solo estadio en Uruguay.",o:["Verdadero","Falso"],a:1,exp:"Falso. El Mundial de 1930 usó 3 estadios en Montevideo: el Estadio Centenario (construido para el evento), el Estadio Gran Parque Central y el Estadio Pocitos.",extra:"El Estadio Centenario fue inaugurado durante el torneo y fue la sede de la final Uruguay vs Argentina (4-2). El torneo se jugó íntegramente en Montevideo, solo en esa ciudad."},
  {t:"m",q:"¿Qué debut mundialista hizo Kylian Mbappé en Rusia 2018 que solo Pelé había logrado antes?",o:["Ganó la Bota de Oro","Marcó en la final del Mundial siendo menor de 20 años","Metió 4 goles en un solo partido","Fue el jugador más joven en jugar un Mundial"],a:1,exp:"Mbappé se convirtió en 2018 en el segundo jugador menor de 20 años en marcar en una final mundialista, después de Pelé en 1958. Francia ganó esa final 4-2 a Croacia.",extra:"Mbappé tenía 19 años en la final de 2018. Pelé tenía 17 cuando marcó ante Suecia en 1958. Ambos consiguieron el título en la misma oportunidad."},

  // ── MUNDIALES Y CURIOSIDADES FINALES ─────────────────────────
  {t:"m",q:"¿Quién fue el goleador del primer Mundial de 1930, con el récord de 8 goles en un solo torneo?",o:["Guillermo Stábile (Argentina)","Pedro Petrone (Uruguay)","Bert Patenaude (USA)","Héctor Castro (Uruguay)"],a:0,exp:"Guillermo Stábile (Argentina) marcó 8 goles en el Mundial de 1930, siendo el máximo goleador del primer torneo. El récord en una sola edición fue superado después.",extra:"Stábile debutó en el Mundial siendo el reemplazante de un titular. Con 8 goles llevó a Argentina a la final, donde perdieron ante Uruguay 2-4. Es el mayor debut mundialista de la historia."},
  {t:"m",q:"¿Quién marcó el primer hat-trick en la historia de los Mundiales en el torneo de 1930?",o:["Guillermo Stábile","Bert Patenaude (USA)","Pedro Cea (Uruguay)","Wilfried Van Moer"],a:1,exp:"Bert Patenaude (Estados Unidos) anotó el primer hat-trick de la historia mundialista el 17 de julio de 1930 ante Paraguay. USA ganó ese partido 3-0.",extra:"El hat-trick de Patenaude fue reconocido oficialmente por la FIFA recién en 2006 tras revisar los archivos históricos. Antes se atribuía erróneamente a otro jugador."},
  {t:"m",q:"¿Qué selección ha disputado más finales mundialistas perdidas?",o:["Francia","Brasil","Alemania","Argentina"],a:2,exp:"Alemania es el país con más finales perdidas: cayó en 1966 (vs Inglaterra), 1982 (vs Italia), 1986 (vs Argentina) y 2002 (vs Brasil). Tiene 4 finales perdidas.",extra:"Sumando las ganadas (1954, 1974, 1990, 2014), Alemania ha jugado 8 finales en total, más que cualquier otro país. Es la selección más consistente en la historia del torneo."},
  {t:"f",q:"Just Fontaine (Francia) marcó 13 goles en el Mundial de 1958, el récord de goles en un solo torneo que aún se mantiene.",o:["Verdadero","Falso"],a:0,exp:"Verdadero. Just Fontaine marcó 13 goles en el Mundial de Suecia 1958 en solo 6 partidos. Es el récord de goles en una sola edición mundialista que no ha sido igualado.",extra:"Fontaine marcó 4 goles en un solo partido (vs Alemania Occidental por el tercer puesto). Francia terminó 3ra. La carrera de Fontaine terminó prematuramente por lesiones."},
  {t:"m",q:"¿Cuál es el mayor número de goles marcados por una selección en un solo partido de fases finales?",o:["8 goles","10 goles","12 goles","9 goles"],a:1,exp:"Hungría marcó 10 goles ante El Salvador en España 1982 (10-1). Antes, Austria marcó 7 ante Suiza en 1954, pero la goleada húngara es la mayor final de la historia.",extra:"Laszlo Kiss marcó un hat-trick en solo 7 minutos como suplente en ese partido, convirtiéndose en el jugador que marcó más rápido un hat-trick desde el banco."},
  {t:"m",q:"¿Qué jugador fue el último en marcar un hat-trick en una final mundialista, hazaña que realizó en 1966?",o:["Pelé","Just Fontaine","Geoff Hurst","Eusébio"],a:2,exp:"Geoff Hurst marcó el único hat-trick de una final mundialista el 30 de julio de 1966, cuando Inglaterra venció a Alemania Occidental 4-2 en el Estadio Wembley.",extra:"Su tercer gol es el más controvertido: el balón pegó en el travesaño y rebotó dentro (o fuera) de la línea. El árbitro lo dio como gol tras consultar con el juez de línea."},
  {t:"m",q:"¿Cuántos cupos para el Mundial 2026 tiene la AFC (Confederación Asiática)?",o:["6 cupos","8 cupos + repechaje","10 cupos","5 cupos"],a:1,exp:"Asia tiene 8 cupos directos más uno adicional en el repechaje intercontinental para el Mundial 2026. En el formato de 32 equipos tenía solo 4,5 plazas.",extra:"El aumento de cupos para Asia refleja el crecimiento del fútbol en la región. Japón, Corea del Sur, Arabia Saudita y otros países compiten regularmente a buen nivel."},
  {t:"m",q:"¿Qué récord estableció el delantero francés Kylian Mbappé al convertirse en el máximo goleador de Qatar 2022?",o:["Primer jugador en marcar 8 goles desde Ronaldo 2002","El goleador más joven de una final","El primer europeo en ganar la Bota de Oro desde 1998","Primer jugador en marcar en 4 fases distintas del torneo"],a:0,exp:"Mbappé marcó 8 goles en Qatar 2022, igualando el récord de Ronaldo Nazário en 2002 para el máximo goleador de un torneo de 32 equipos.",extra:"El hat-trick de Mbappé en la final fue excepcional pero no alcanzó para Francia. Sus 3 goles en los últimos 15 minutos igualaron el partido a 3-3 antes de los penales."},
  {t:"m",q:"¿Cuántas veces ha ganado Argentina el Mundial y cuáles son los años?",o:["2 veces: 1978 y 1986","3 veces: 1978, 1986 y 2022","2 veces: 1986 y 2022","4 veces"],a:1,exp:"Argentina ganó 3 Mundiales: 1978 (local, con César Menotti), 1986 (México, con Maradona) y 2022 (Qatar, con Lionel Messi).",extra:"En 1978 el título fue polémico por el régimen militar en el poder. En 1986 fue el de Maradona. En 2022 fue el de Messi, quizás el más emocionante de los tres."},
  {t:"m",q:"¿Qué selección ganó el Mundial como local más recientemente?",o:["Brasil 2014","Argentina 1978","Francia 1998","Alemania 2006"],a:2,exp:"Francia ganó el Mundial de 1998 jugando como local, venciendo a Brasil 3-0 en la final. Fue el último título obtenido por un país anfitrión.",extra:"Desde Francia 1998, ningún anfitrión ha ganado el torneo. Brasil 2014 fue eliminado en semifinales (7-1 vs Alemania) y Qatar 2022 no pasó de grupos."},
  {t:"m",q:"¿Cuántos goles se marcaron en total en el Mundial de Qatar 2022?",o:["142 goles","172 goles","172 goles","156 goles"],a:1,exp:"En Qatar 2022 se marcaron 172 goles en 64 partidos, con un promedio de 2,69 goles por partido, siendo uno de los torneos con más goles por partido de la historia reciente.",extra:"El promedio de goles por partido fue el más alto desde el Mundial de Francia 1998. La calidad de los atacantes y el ritmo del torneo contribuyeron al festival de goles."},
  {t:"m",q:"¿Qué portero se consagró como héroe en la final del Mundial 2022 tapando dos penales ante Francia?",o:["David De Gea","Alisson Becker","Emiliano Martínez","Hugo Lloris"],a:2,exp:"Emiliano Martínez (Argentina) fue clave en la final de Qatar 2022: atajó el penal de Kingsley Coman y la definición de Randal Kolo Muani para que Argentina ganara por penales.",extra:"'El Dibu' Martínez también fue figura en semifinales ante Croacia. Su provocativa celebración del Guante de Oro generó controversia pero reflejó su intensidad competitiva."},
  {t:"m",q:"¿Qué selección latinoamericana eliminó a Polonia y llegó a cuartos de final en el Mundial de Qatar 2022?",o:["Ecuador","México","Perú","Australia"],a:1,exp:"Australia eliminó a Polonia... en realidad fue Australia quien fue a octavos. México no pasó de grupos. En cuartos de final de LATAM en 2022 estuvieron Brasil y Argentina.",extra:"Brasil llegó a cuartos donde perdió ante Croacia en penales. Argentina superó Países Bajos en cuartos. México quedó eliminado en la fase de grupos pese a ganar 2-1 a Polonia."},
  {t:"f",q:"México ha sido eliminado en la fase de octavos de final (ronda de 16) en sus últimas 7 participaciones consecutivas en el Mundial.",o:["Verdadero","Falso"],a:0,exp:"Verdadero. Desde 1994 hasta 2018, México llegó siempre a octavos y siempre cayó. En Qatar 2022 ni siquiera llegó a esa fase, rompiendo la racha pero de la peor manera.",extra:"La 'maldición del quinto partido' (no pasar de octavos) se convirtió en un fenómeno cultural en México. Romperla sigue siendo el gran objetivo de la selección azteca."},
  {t:"m",q:"¿Cuál es el nombre del estadio principal de la ciudad de Dallas que será sede del Mundial 2026?",o:["Cowboys Stadium","Mercedes-Benz Stadium","AT&T Stadium","Globe Life Field"],a:2,exp:"El AT&T Stadium (antes conocido como Cowboys Stadium) en Arlington, Texas, es el estadio sede del Mundial 2026 en el área de Dallas, con capacidad para 100.000 espectadores.",extra:"Es el estadio techado más grande del mundo y uno de los más modernos de los EE.UU. Tiene una pantalla gigante central que es la más grande en un estadio deportivo."},
  {t:"m",q:"¿En qué estadio de Los Ángeles se jugó la final del Mundial de 1994 en Estados Unidos?",o:["SoFi Stadium","Rose Bowl","Memorial Coliseum","Dignity Health Sports Park"],a:1,exp:"La final del Mundial 1994 se jugó en el Rose Bowl de Pasadena (Los Ángeles), con más de 94.000 espectadores presenciando el Brasil vs Italia.",extra:"El Rose Bowl también será sede del Mundial 2026. Es uno de los estadios más históricos de EE.UU. con más de 100 años de historia y fue sede también de los JJOO 1984."},
  {t:"m",q:"¿Cuántas veces fue campeón del mundo Didier Deschamps: como jugador y como entrenador de Francia?",o:["Solo 1 vez como jugador","1 vez como jugador (1998) y 1 vez como entrenador (2018)","2 veces como jugador","2 veces como entrenador"],a:1,exp:"Didier Deschamps ganó el Mundial de 1998 como capitán de Francia y el de 2018 como entrenador de la misma selección. Es uno de los pocos en lograrlo en ambos roles.",extra:"El único otro jugador/entrenador bicampeón fue Franz Beckenbauer (jugador 1974, entrenador 1990 con Alemania). Deschamps igualó esa hazaña en 2018."},
  {t:"m",q:"¿Qué selección venció a la ampliamente favorita España en la final del Mundial de Sudáfrica 2010?",o:["Brasil","Países Bajos","Alemania","Uruguay"],a:1,exp:"Países Bajos (Holanda) fue el rival de España en la final del Mundial 2010. España ganó 1-0 con gol de Andrés Iniesta en el minuto 116 de la prórroga.",extra:"Fue el primer Mundial de España. La selección había dominado el fútbol mundial con el 'tiki-taka' de Guardiola/Del Bosque. Iniesta marcó el gol del título y fue figura del torneo."},
  {t:"m",q:"¿Qué jugador argentino marcó el gol a los 17 años en el Mundial de 2022 convirtiéndose en uno de los más jóvenes en marcar en una final?",o:["Lautaro Martínez","Ángel Di María","Julián Álvarez","Paulo Dybala"],a:2,exp:"Julián Álvarez no marcó en la final, fue Ángel Di María. Pero Julián Álvarez fue el segundo goleador del torneo con 4 goles. Di María marcó en la final a los 34 años.",extra:"Di María abrió el marcador en la final ante Francia con un gol de penal en el primer tiempo. Fue uno de sus mejores partidos con Argentina en un torneo mundialista."},
  {t:"m",q:"¿Cuántos mundiales dirigió Marcelo Bielsa, el 'Loco' conocido por su influencia en el fútbol moderno?",o:["1 Mundial","2 Mundiales","3 Mundiales","Nunca dirigió un Mundial"],a:0,exp:"Marcelo Bielsa dirigió un único Mundial: Francia 1998 con Argentina, donde llegaron a cuartos de final siendo eliminados por Países Bajos en penales (1-1 después de 90 min).",extra:"Bielsa llevó a Argentina con un excelente juego pero la eliminación ante Holanda fue polémica. Su huella como técnico ha marcado a generaciones de entrenadores como Guardiola y Klopp."},
  {t:"f",q:"El Mundial 2026 será la primera Copa del Mundo en la historia con 48 equipos participantes.",o:["Verdadero","Falso"],a:0,exp:"Verdadero. El Mundial 2026 inaugurará el formato de 48 selecciones, un aumento del 50% respecto a los 32 equipos que participaron desde 1998 hasta 2022.",extra:"La FIFA aprobó el nuevo formato en 2017. Hubo debates sobre si el aumento de equipos diluía la calidad, pero también argumentos sobre mayor representación global del fútbol."},
  {t:"m",q:"¿Quién será el único estadio en la historia del fútbol en albergar partidos de tres Copas del Mundo diferentes (1970, 1986 y 2026)?",o:["Camp Nou (Barcelona)","Wembley Stadium (Londres)","Estadio Azteca (Ciudad de México)","Maracaná (Río de Janeiro)"],a:2,exp:"El Estadio Azteca será el único estadio del mundo en albergar partidos de tres ediciones distintas de la Copa del Mundo: 1970, 1986 y 2026.",extra:"En el Azteca de 1970 se jugó la final (Brasil 4-1 Italia). En 1986 se jugó otra final (Argentina 3-2 Alemania) y el gol del siglo de Maradona. En 2026 será sede nuevamente."},

  // ── ESTADIOS: EE.UU. ─────────────────────────────────────────
  {t:"m",q:"¿Cómo se llama el estadio de Dallas (Arlington, Texas) sede del Mundial 2026, hogar de los Dallas Cowboys?",o:["NRG Stadium","AT&T Stadium","State Farm Stadium","SoFi Stadium"],a:1,exp:"El AT&T Stadium en Arlington (Dallas) es uno de los estadios techados más grandes del mundo, sede del Mundial 2026 y casa de los Dallas Cowboys de la NFL.",extra:"Tiene capacidad para más de 100.000 espectadores con la configuración expandida. Es conocido por su pantalla gigante colgante, la mayor en un estadio en el mundo."},
  {t:"m",q:"¿Cómo se llama el estadio de Miami (Miami Gardens) que albergará partidos del Mundial 2026?",o:["Sun Life Stadium","American Airlines Arena","Hard Rock Stadium","FTX Arena"],a:2,exp:"El Hard Rock Stadium, ubicado en Miami Gardens (no en la ciudad de Miami propiamente), es la sede del Mundial 2026 en el área metropolitana de Miami.",extra:"Es el hogar de los Miami Dolphins (NFL) y el Inter Miami CF (MLS), el equipo donde jugó Lionel Messi en 2023. Tiene capacidad para unos 65.000 espectadores."},
  {t:"m",q:"¿Cómo se llama el estadio de Seattle sede del Mundial 2026, hogar de los Seattle Sounders de la MLS?",o:["CenturyLink Field","Clink Field","T-Mobile Park","Lumen Field"],a:3,exp:"Lumen Field en Seattle (anteriormente CenturyLink Field) es la sede del Mundial 2026 en esa ciudad, compartida por los Seattle Seahawks (NFL) y los Seattle Sounders (MLS).",extra:"Los Seattle Sounders son uno de los equipos de MLS con mayor asistencia promedio de toda la liga norteamericana, lo que hace de Lumen Field una sede con tradición futbolera."},
  {t:"m",q:"¿Cómo se llama el estadio de Kansas City sede del Mundial 2026, uno de los más ruidosos de la NFL?",o:["Kauffman Stadium","Arrowhead Stadium","Lamar Hunt Field","Sprint Center"],a:1,exp:"Arrowhead Stadium en Kansas City, Missouri, es la sede del Mundial 2026 en esa ciudad. Es el estadio de los Kansas City Chiefs (NFL), reconocido como uno de los más ruidosos del mundo.",extra:"Kansas City también tiene el Sporting KC de la MLS (que juega en otro estadio), pero Arrowhead fue elegido por su mayor capacidad para el Mundial."},
  {t:"m",q:"¿Cómo se llama el estadio de Boston/Foxborough sede del Mundial 2026, hogar de los New England Patriots?",o:["TD Garden","Gillette Stadium","Fenway Park","Foxboro Arena"],a:1,exp:"Gillette Stadium en Foxborough, Massachusetts (cerca de Boston) es la sede del Mundial 2026 en esa área. Es el hogar de los New England Patriots (NFL) y el New England Revolution (MLS).",extra:"Foxborough está a unos 45 km de Boston. La combinación NFL/MLS lo hace ya familiar para el fútbol. Tiene capacidad para unos 65.000 espectadores."},
  {t:"m",q:"¿Cómo se llama el estadio de Filadelfia sede del Mundial 2026, donde juegan los Eagles de la NFL?",o:["Citizens Bank Park","Wells Fargo Center","Lincoln Financial Field","Independence Stadium"],a:2,exp:"Lincoln Financial Field en Filadelfia es la sede del Mundial 2026 en esa ciudad. Es el hogar de los Philadelphia Eagles (NFL) y el Philadelphia Union (MLS) juega cerca.",extra:"Filadelfia tiene una historia deportiva muy rica. Su inclusión en el Mundial 2026 refleja la importancia del área metropolitana como mercado futbolístico."},
  {t:"m",q:"¿Cómo se llama el estadio del área de San Francisco (Santa Clara, California) sede del Mundial 2026?",o:["Oracle Park","AT&T Park","Chase Center","Levi's Stadium"],a:3,exp:"Levi's Stadium en Santa Clara (Silicon Valley) es la sede del Mundial 2026 para el área de San Francisco. Es el hogar de los San Francisco 49ers (NFL).",extra:"Santa Clara está a unos 75 km de San Francisco. La sede se eligió porque Levi's Stadium tiene mejor infraestructura y accesibilidad que un hipotético estadio en la ciudad."},
  {t:"m",q:"¿Cómo se llama el estadio de Atlanta sede del Mundial 2026, uno de los más modernos de EE.UU.?",o:["Georgia Dome","Truist Park","State Farm Arena","Mercedes-Benz Stadium"],a:3,exp:"Mercedes-Benz Stadium en Atlanta es la sede del Mundial 2026. Inaugurado en 2017, es uno de los estadios más modernos del mundo, con un techo retráctil único.",extra:"Es el hogar del Atlanta Falcons (NFL) y el Atlanta United FC (MLS). El Atlanta United fue campeón de MLS en 2018 con un estadio constantemente lleno, lo que lo hace ideal."},
  {t:"m",q:"¿Qué equipo de la MLS que juega en el Mercedes-Benz Stadium de Atlanta fue campeón de MLS en 2018?",o:["Atlanta Braves","Atlanta Hawks","Atlanta United FC","Atlanta FC"],a:2,exp:"Atlanta United FC ganó la MLS Cup en 2018, su segundo año de existencia, llenando el Mercedes-Benz Stadium con promedios récord de asistencia para la liga.",extra:"Atlanta United demostró que el fútbol puede tener grandes audiencias en EE.UU. Su éxito fue clave para justificar a Atlanta como sede del Mundial 2026."},
  {t:"m",q:"¿El estadio Rose Bowl de Los Ángeles que albergará el Mundial 2026 también fue sede de la final del Mundial de 1994?",o:["Verdadero","Falso"],a:0,exp:"Verdadero. El Rose Bowl en Pasadena, Los Ángeles, fue sede de la final de USA 1994 (Brasil vs Italia) y volverá a serlo en el Mundial 2026 como sede de partidos.",extra:"El Rose Bowl tiene más de 100 años de historia y es uno de los estadios más icónicos de EE.UU. Su capacidad para el fútbol es de aproximadamente 92.000 espectadores."},
  {t:"m",q:"¿En qué ciudad específica está el Rose Bowl, el estadio sede del Mundial 2026 del área de Los Ángeles?",o:["Los Ángeles (centro)","Inglewood","Pasadena","Anaheim"],a:2,exp:"El Rose Bowl está ubicado en Pasadena, California, en el área metropolitana de Los Ángeles. Es hogar de la 'Rose Bowl Game' de fútbol americano universitario.",extra:"Pasadena es conocida por el Rose Bowl Game y el Rose Parade. El estadio es un Monumento Histórico Nacional de EE.UU. y es emblemático en la historia del deporte americano."},
  {t:"m",q:"¿Cuántos estadios del área de Los Ángeles serán sedes del Mundial 2026?",o:["Solo 1 (el Rose Bowl)","2 estadios (Rose Bowl y SoFi Stadium)","3 estadios","4 estadios"],a:1,exp:"Los Ángeles tendrá dos sedes en el Mundial 2026: el Rose Bowl (Pasadena) y el SoFi Stadium (Inglewood), convirtiéndola en la ciudad con más sedes del torneo.",extra:"SoFi Stadium, inaugurado en 2020, es el estadio más moderno y caro jamás construido (5,5 mil millones de dólares). Es el hogar de los Rams y Chargers de la NFL."},

  // ── ESTADIOS: CANADÁ Y MÉXICO ─────────────────────────────────
  {t:"m",q:"¿Cómo se llama el estadio de Vancouver (Canadá) sede del Mundial 2026?",o:["BC Place","Rogers Centre","GM Place","Commonwealth Stadium"],a:0,exp:"BC Place en Vancouver es la sede del Mundial 2026 en esa ciudad. Es el primer estadio techado de Canadá y tiene capacidad para unos 54.500 espectadores.",extra:"BC Place también fue sede de la final del Mundial Femenino 2015. Para el Mundial masculino 2026, se instalará césped natural temporal en reemplazo del sintético habitual."},
  {t:"m",q:"¿Cómo se llama el estadio de Toronto (Canadá) sede del Mundial 2026?",o:["Rogers Centre","BMO Field","Scotiabank Arena","CAA Centre"],a:1,exp:"BMO Field en Toronto es la sede del Mundial 2026 en esa ciudad. Es el estadio de Toronto FC (MLS) y la selección canadiense masculina y femenina.",extra:"BMO Field se expandirá para el Mundial 2026. Su nombre es un homenaje al Banco de Montreal (Bank of Montreal / BMO), el patrocinador del estadio."},
  {t:"m",q:"¿Qué equipo de la MLS tiene como hogar el BMO Field de Toronto, sede del Mundial 2026?",o:["CF Montréal","Vancouver Whitecaps","Toronto FC","Ottawa Fury"],a:2,exp:"Toronto FC es el equipo de MLS con local en el BMO Field. Fue fundado en 2007 y es uno de los clubes más exitosos de la MLS, campeón en 2017.",extra:"Toronto FC fue el primer equipo no estadounidense de la MLS. La ciudad de Toronto tiene la mayor concentración de inmigrantes del mundo, con una gran diversidad de fans de fútbol."},
  {t:"m",q:"¿Cómo se llama el estadio de Guadalajara (México) sede del Mundial 2026, hogar del Club Deportivo Guadalajara (Chivas)?",o:["Estadio Jalisco","Estadio Azteca Norte","Estadio Akron","Estadio 3 de Marzo"],a:2,exp:"El Estadio Akron (anteriormente Omnilife o Chivas Stadium) en Guadalajara es la sede del Mundial 2026 en esa ciudad y el hogar del famoso club Chivas.",extra:"El Estadio Akron fue inaugurado en 2010 y tiene capacidad para unos 49.000 espectadores. Su diseño moderno y colorido lo hace uno de los estadios más fotogénicos de México."},
  {t:"m",q:"¿Cómo se llama el estadio de Monterrey (México) sede del Mundial 2026, hogar del CF Monterrey (Rayados)?",o:["Estadio Universitario","Estadio Azteca Norte","Estadio BBVA","Estadio TechNM"],a:2,exp:"El Estadio BBVA (también conocido como Estadio Bancomer o Rayados) en Monterrey es la sede del Mundial 2026 y el hogar del CF Monterrey (Los Rayados).",extra:"El Estadio BBVA tiene capacidad para unos 53.000 espectadores y es considerado uno de los mejores estadios de América Latina. Fue inaugurado en 2015."},
  {t:"m",q:"¿Cuánta capacidad tiene el Estadio Azteca de Ciudad de México, sede del partido inaugural del Mundial 2026?",o:["65.000 espectadores","75.000 espectadores","Aproximadamente 87.000 espectadores","105.000 espectadores"],a:2,exp:"El Estadio Azteca tiene capacidad para unos 87.000 espectadores, siendo uno de los estadios de fútbol más grandes del mundo.",extra:"Fue inaugurado en 1966 y albergó las finales de los Mundiales de 1970 y 1986. Para el Mundial 2026 fue renovado, incluyendo mejoras en la iluminación y los accesos."},

  // ── LA CANDIDATURA "UNITED 2026" ──────────────────────────────
  {t:"m",q:"¿Cuál fue el nombre oficial de la candidatura conjunta de USA, Canadá y México para organizar el Mundial 2026?",o:["North America 2026","Triple Host 2026","United 2026","CONCACAF 2026"],a:2,exp:"La candidatura se llamó 'United 2026', un nombre que reflejaba la unión de tres naciones norteamericanas para organizar el torneo más grande de la historia.",extra:"El logo de United 2026 mostraba a los tres países como una unidad. La cooperación trinacional fue un argumento clave para persuadir a la FIFA frente a la candidatura de Marruecos."},
  {t:"m",q:"¿En qué ciudad del mundo se decidió la candidatura del Mundial 2026, durante el 68° Congreso de la FIFA en 2018?",o:["París","Zúrich","Moscú","Berlín"],a:2,exp:"El 68° Congreso de la FIFA se celebró en Moscú, Rusia, el 13 de junio de 2018 (durante el Mundial 2018), donde se votó a favor de la candidatura United 2026.",extra:"La elección durante el propio Mundial de Rusia fue peculiar. Muchos delegados estaban en Moscú para el torneo y aprovecharon para votar la sede del siguiente (2026)."},
  {t:"m",q:"¿Contra qué candidatura compitió 'United 2026' (USA/Canadá/México) en la votación de la FIFA en 2018?",o:["Alemania","Qatar","Marruecos","Indonesia"],a:2,exp:"Marruecos presentó su candidatura para el Mundial 2026 por quinta vez (habían intentado organizar ediciones anteriores sin éxito). Perdió ante United 2026 en la votación.",extra:"Era la quinta candidatura de Marruecos, tras intentarlo en 1994, 1998, 2006 y 2010. Finalmente obtuvo el Mundial 2030 como co-organizador junto a España y Portugal."},
  {t:"f",q:"Marruecos finalmente obtendrá su primer Mundial como co-anfitrión en 2030 junto a España y Portugal.",o:["Verdadero","Falso"],a:0,exp:"Verdadero. Marruecos, tras perder la sede del 2026 ante United 2026, fue seleccionado como co-organizador del Mundial 2030 junto a España y Portugal, su primer Mundial como sede.",extra:"El 2030 también tendrá partidos conmemorativos en Uruguay, Argentina y Paraguay para celebrar el centenario del primer Mundial de 1930."},

  // ── SELECCIÓN DE ESTADOS UNIDOS ──────────────────────────────
  {t:"m",q:"¿En qué Mundial no clasificó la selección de EE.UU., provocando una crisis en el fútbol norteamericano?",o:["Brasil 2014","Rusia 2018","Qatar 2022","Sudáfrica 2010"],a:1,exp:"EE.UU. no clasificó para el Mundial de Rusia 2018 tras perder ante Trinidad y Tobago 1-2 en la última fecha de las eliminatorias CONCACAF.",extra:"Fue la primera vez desde 1986 que EE.UU. no se clasificaba. La derrota fue un golpe enorme que generó una gran renovación en la selección, el cuerpo técnico y la estructura del fútbol americano."},
  {t:"m",q:"¿En qué fase del Mundial de 2002 (Corea-Japón) llegó la selección de EE.UU., su mejor resultado en la era moderna?",o:["Octavos de final","Cuartos de final","Semifinales","Solo fase de grupos"],a:1,exp:"En el Mundial de 2002, EE.UU. llegó a cuartos de final, su mejor resultado desde la semifinal de 1930. Fueron eliminados por Alemania 0-1.",extra:"En el camino a cuartos, EE.UU. venció a Portugal 3-2, empató con Corea del Sur y venció a México en octavos. Fue la generación de Landon Donovan, Clint Dempsey y DaMarcus Beasley."},
  {t:"m",q:"¿Quién es el jugador estrella del USMNT (selección de EE.UU.) para el Mundial 2026, capitán y figura en el AC Milan?",o:["Weston McKennie","Tyler Adams","Giovanni Reyna","Christian Pulisic"],a:3,exp:"Christian Pulisic es la figura principal del fútbol estadounidense, mediapunta del AC Milan que lidera la selección del USMNT en el ciclo mundialista 2026.",extra:"Pulisic es el primer jugador americano en fichar por el AC Milan. Fue figura clave en la clasificación de EE.UU. para Qatar 2022 y es el ícono de la nueva generación de fútbol americano."},
  {t:"m",q:"¿En qué club europeo de élite juega Weston McKennie, centrocampista de EE.UU. para el Mundial 2026?",o:["Borussia Dortmund","Atlético de Madrid","Leeds United","Juventus"],a:3,exp:"Weston McKennie juega en la Juventus de Turín (Italia), siendo uno de los centrocampistas americanos con más nivel en Europa en el ciclo 2026.",extra:"McKennie fue clave en la clasificación de EE.UU. para Qatar 2022. Su paso por la Scuderia italiana le dio experiencia internacional de alto nivel en el fútbol europeo."},
  {t:"m",q:"¿Cuál fue el torneo continental que organizó EE.UU. en 2024, sirviendo como ensayo general para el Mundial 2026?",o:["Copa Oro 2024","Copa América 2024","Liga de Naciones CONCACAF 2024","Nations League UEFA 2024"],a:1,exp:"La Copa América 2024 se celebró en EE.UU. en junio-julio de 2024 con 16 selecciones. Fue un ensayo clave para la logística y organización del Mundial 2026.",extra:"La Copa América 2024 usó muchos de los mismos estadios del Mundial 2026, siendo una prueba real de las sedes. Argentina ganó el torneo, derrotando a Colombia en la final."},
  {t:"m",q:"¿Qué selección ganó la Copa América 2024 organizada en EE.UU., consolidándose como favorita para el Mundial 2026?",o:["Brasil","Colombia","Uruguay","Argentina"],a:3,exp:"Argentina ganó la Copa América 2024 en los EE.UU., su segundo título consecutivo de la Copa América, convirtiéndose en bicampeón y afirmando su candidatura en el 2026.",extra:"La final fue en el Hard Rock Stadium de Miami. Colombia era el rival. Argentina ganó 1-0 con gol de Lautaro Martínez en el tiempo extra. Fue el último gran torneo de Messi."},
  {t:"m",q:"¿Contra quién jugó y cómo terminó la final de la Copa América 2024?",o:["Argentina 1-0 Colombia (prórroga)","Argentina 2-1 Brasil","Colombia 1-0 Argentina","Uruguay 2-0 Argentina"],a:0,exp:"Argentina venció a Colombia 1-0 en la prórroga de la final de la Copa América 2024, con gol de Lautaro Martínez. La final se jugó en el Hard Rock Stadium de Miami.",extra:"Colombia hizo un torneo excelente bajo la conducción de Néstor Lorenzo. El gol tardío de Lautaro Martínez fue el que le dio el bicampeonato a Argentina."},
  {t:"f",q:"EE.UU. llegó a las semifinales de la Copa América 2024 que organizó en su propio suelo.",o:["Verdadero","Falso"],a:1,exp:"Falso. EE.UU. fue eliminado en cuartos de final de la Copa América 2024 por Uruguay, siendo una de las decepciones del torneo para los locales.",extra:"La eliminación de EE.UU. generó debate sobre su nivel de preparación para el Mundial 2026. Sin embargo, la derrota también fue un incentivo para mejorar antes de ser sede."},
  {t:"m",q:"¿Qué liga profesional de fútbol de EE.UU. ha crecido de menos de 10 equipos en 1996 a más de 30 equipos para el 2026?",o:["NASL","NWSL","USL","MLS (Major League Soccer)"],a:3,exp:"La MLS (Major League Soccer) fundada en 1996 con 10 equipos ha crecido hasta más de 30 franquicias para el ciclo 2026, siendo la liga más grande del continente.",extra:"La MLS fue creada como condición de la FIFA para darle a EE.UU. el Mundial de 1994. Desde entonces, el fútbol americano creció enormemente. Jugadores como Messi y Riqui Puig llegaron a la liga."},
  {t:"m",q:"¿Qué famoso jugador de primer nivel mundial fichó por el Inter Miami de la MLS en 2023, dando un enorme impulso al fútbol en EE.UU.?",o:["Cristiano Ronaldo","Kylian Mbappé","Neymar Jr.","Lionel Messi"],a:3,exp:"Lionel Messi fichó por el Inter Miami CF en julio de 2023, convirtiendo a la MLS en foco mundial de atención y disparando ventas de entradas, televisión y merchandising en EE.UU.",extra:"La llegada de Messi a la MLS fue el mayor fichaje en la historia de la liga. El efecto 'Messi' multiplicó el interés por el fútbol en EE.UU. en el período previo al Mundial 2026."},

  // ── SELECCIÓN DE CANADÁ ───────────────────────────────────────
  {t:"m",q:"¿En qué año fue la única participación de Canadá en un Mundial masculino antes de Qatar 2022?",o:["1978","1982","1986","1990"],a:2,exp:"Canadá participó por primera vez en un Mundial masculino en México 1986. No ganó ningún partido ni marcó goles, siendo eliminada en primera ronda.",extra:"Desde 1986, Canadá no volvió a clasificar a un Mundial masculino hasta Qatar 2022, una sequía de 36 años que convirtió la clasificación para Qatar en un hito histórico."},
  {t:"m",q:"¿Cuántos años pasaron entre la única participación mundialista de Canadá en 1986 y su vuelta en Qatar 2022?",o:["24 años","30 años","36 años","40 años"],a:2,exp:"Pasaron 36 años entre México 1986 y Qatar 2022. Durante ese tiempo, Canadá transformó su fútbol, invirtió en academias y formó la generación más talentosa de su historia.",extra:"La clasificación para Qatar 2022 fue celebrada como un triunfo histórico en Canadá. El fútbol ganó popularidad masiva en el país, que antes estaba dominado por el hockey sobre hielo."},
  {t:"m",q:"¿Quién es el jugador más famoso de la selección masculina de Canadá, ala del Bayern Munich conocido por su velocidad?",o:["Jonathan David","Tajon Buchanan","Cyle Larin","Alphonso Davies"],a:3,exp:"Alphonso Davies es la mayor estrella del fútbol canadiense. Lateral izquierdo del Bayern Munich (Alemania), es conocido por su excepcional velocidad y calidad técnica.",extra:"Davies llegó a Canadá como refugiado de Liberia. Se convirtió en uno de los mejores laterales del mundo y es el ícono de la generación canadiense que busca brillar en el 2026."},
  {t:"m",q:"¿En qué club europeo juega Alphonso Davies, la estrella de la selección de Canadá para el Mundial 2026?",o:["Manchester City","Paris Saint-Germain","Bayern Munich","Real Madrid"],a:2,exp:"Alphonso Davies juega en el Bayern Munich de Alemania, donde ganó la Champions League 2020 y múltiples Bundesligas, convirtiéndose en uno de los mejores laterales del mundo.",extra:"Davies fue comprado por el Bayern a los 17 años. Su historia de refugiado que llegó a la cima del fútbol mundial es una de las más inspiradoras del deporte actual."},
  {t:"m",q:"¿Quién es el máximo goleador histórico de la selección masculina de Canadá, delantero que juega en Ligue 1 de Francia?",o:["Cyle Larin","Tajon Buchanan","Jonathan David","Evan Cavallini"],a:2,exp:"Jonathan David es el máximo goleador histórico de la selección canadiense masculina. Juega en el LOSC Lille de Francia y es uno de los mejores delanteros jóvenes de Europa.",extra:"David nació en Brooklyn (EE.UU.) de padres haitianos, creció en Bélgica y representa a Canadá. Su efectividad en el Lille lo convirtió en uno de los delanteros más codiciados de Europa."},
  {t:"f",q:"El equipo femenino de Canadá ganó la medalla de oro en fútbol femenino en los Juegos Olímpicos de Tokio 2020.",o:["Verdadero","Falso"],a:0,exp:"Verdadero. La selección femenina de Canadá ganó el oro en Tokio 2021 (Juegos Olímpicos de 2020), venciendo a Suecia en los penales. Fue el mayor logro del fútbol canadiense.",extra:"El triunfo olímpico femenino encendió el interés por el fútbol en Canadá. Christine Sinclair, la máxima goleadora en la historia del fútbol internacional, fue figura clave."},
  {t:"m",q:"¿Qué apodo recibe la selección masculina de Canadá en el ámbito futbolístico?",o:["The Maple Leafs","Les Rouges","The Canucks","Team Canada"],a:1,exp:"'Les Rouges' (Los Rojos) es el apodo de la selección masculina de Canadá, por el color rojo característico de su uniforme y de la bandera canadiense.",extra:"El equipo también puede ser referenciado como 'The Reds'. La identidad visual del equipo, con el rojo y el arce, conecta claramente con los símbolos nacionales de Canadá."},

  // ── SELECCIÓN DE MÉXICO ───────────────────────────────────────
  {t:"m",q:"¿Qué apodo tiene la selección de fútbol mexicana, una de las más populares de Latinoamérica?",o:["La Roja","Los Aztecas","El Tri","Los Verdes"],a:2,exp:"'El Tri' es el apodo de la selección mexicana, en referencia a los tres colores de la bandera: verde, blanco y rojo.",extra:"El nombre oficial del equipo es 'Club de Fútbol de la Selección Nacional Mexicana' pero en todo el mundo se conoce simplemente como 'El Tri'. Tiene millones de seguidores en todo el mundo."},
  {t:"m",q:"¿A qué fase del Mundial llega México habitualmente desde 1994, en lo que los hinchas llaman el 'quinto partido'?",o:["Fase de grupos","Cuartos de final","Semifinales","Octavos de final (ronda de 16)"],a:3,exp:"México ha llegado a los octavos de final (ronda de 16) en cada Mundial desde 1994 hasta 2018, siendo siempre eliminado en ese punto: el 'quinto partido' al que nunca llegan.",extra:"La 'maldición del quinto partido' es un fenómeno cultural en México. En Qatar 2022, México ni siquiera llegó a octavos, rompiendo la racha pero de la peor manera posible."},
  {t:"m",q:"¿Cuántas participaciones consecutivas en Mundiales acumuló México antes de Qatar 2022?",o:["5 clasificaciones","8 clasificaciones","10 clasificaciones","12 clasificaciones"],a:1,exp:"México clasificó a 8 Mundiales consecutivos entre 1994 y 2018. Esta racha de consistencia lo convirtió en uno de los equipos más regulares de CONCACAF.",extra:"La racha de México fue impresionante para una región donde la clasificación es muy disputada. Jugadores como Hugo Sánchez, Cuauhtémoc Blanco y Javier 'Chicharito' Hernández marcaron esas eras."},
  {t:"m",q:"¿Cuál es el mayor resultado de México en los Mundiales que haya jugado, más allá de sus rondas de 16 habituales?",o:["Octavos de final (ronda de 16)","Cuartos de final","Semifinales","Tercero en el podio"],a:1,exp:"El mejor resultado de México en Mundiales fue llegar a cuartos de final en México 1970 y México 1986, ambas veces como local, perdiendo ambas veces.",extra:"En 1970 México perdió ante Italia 1-4 en cuartos. En 1986 perdió ante Alemania Occidental en penales (0-0, 1-4 en penales). Sin ser local, nunca superó octavos desde 1994."},
  {t:"m",q:"¿Qué selección latinoamericana es el principal rival de México en el contexto de CONCACAF?",o:["Honduras","Costa Rica","Estados Unidos","Guatemala"],a:2,exp:"Estados Unidos es el principal rival de México en CONCACAF. El 'El Clásico de CONCACAF' es uno de los partidos más apasionantes de la región y tiene décadas de historia.",extra:"La rivalidad USA vs México es intensa tanto dentro del campo como en las gradas. Durante años México dominó; en los últimos tiempos EE.UU. ha igualado y superado la balanza."},

  // ── FORMATO DEL MUNDIAL 2026: DETALLES ───────────────────────
  {t:"m",q:"¿Cuántos partidos como máximo puede jugar un equipo que gana el Mundial 2026?",o:["6 partidos","7 partidos","8 partidos","9 partidos"],a:1,exp:"Con el nuevo formato de 48 equipos, un campeón del Mundial 2026 jugará 7 partidos: 3 de fase de grupos + 1 de ronda de 32 + 1 de cuartos + 1 de semis + 1 final.",extra:"En el formato de 32 equipos, el campeón jugaba 7 partidos también. Con 48 equipos se mantiene el mismo número máximo, pero hay una ronda adicional (ronda de 32) que no existía antes."},
  {t:"m",q:"¿Qué nueva ronda de eliminación directa aparece por primera vez en un Mundial con el formato de 48 equipos de 2026?",o:["Ronda de 64","La ronda de 32 (nuevo round of 32)","Ronda de 24","Play-in stage"],a:1,exp:"La 'ronda de 32' (o round of 32) es completamente nueva en la historia mundialista. Con 32 equipos avanzando desde grupos, se necesita una ronda extra antes de cuartos.",extra:"Esta ronda no existió en ningún Mundial anterior. En el formato de 32 equipos, los 16 clasificados (2 por grupo) iban directamente a octavos. Ahora hay un paso intermedio."},
  {t:"m",q:"¿Cuántos equipos avanzan en total desde la fase de grupos al siguiente round en el Mundial 2026?",o:["24 equipos","28 equipos","32 equipos","36 equipos"],a:2,exp:"Del total de 48 equipos en grupos, avanzan 32: los 2 primeros de cada uno de los 12 grupos (24 equipos) más los 8 mejores terceros clasificados.",extra:"El sistema de 'mejores terceros' ya fue usado en los Mundiales de 1982 a 1994 (con 24 equipos). Lo familiar del sistema ayudó a convencer a la FIFA para adoptarlo de nuevo."},
  {t:"m",q:"¿Qué desventaja para los equipos puede tener el nuevo formato de 48 equipos del Mundial 2026?",o:["Más goles en el torneo","Incertidumbre sobre el rival en la fase eliminatoria hasta el último día de grupos","Menos espectadores en las finales","Partidos más cortos"],a:1,exp:"Con los 8 mejores terceros clasificados, los equipos no sabrán su rival en la ronda de 32 hasta que concluyan todos los grupos, creando incertidumbre logística y táctica.",extra:"Esto también genera más emoción: incluso si un equipo termina tercero, puede clasificar. Cada punto en la fase de grupos importa más, ya que determina el criterio de clasificación."},
  {t:"m",q:"¿Cuántos partidos adicionales al día hay en el Mundial 2026 respecto al Mundial de 2022 con 32 equipos?",o:["20 partidos más","40 partidos más","35 partidos más","50 partidos más"],a:1,exp:"El Mundial 2026 tiene 104 partidos vs 64 del de 2022, es decir, 40 partidos más. Esto implica más fechas, más estadios activos y mayores ingresos por taquilla.",extra:"El aumento de partidos requirió diseñar un calendario más comprimido o distribuido en más días. La logística de 16 ciudades en 3 países ayuda a distribuir mejor la carga de partidos."},
  {t:"m",q:"¿Qué nuevo desafío logístico inédito enfrentarán los equipos en el Mundial 2026 que nunca existió en ediciones anteriores?",o:["Partidos sin porteros","Jugar en tres climas distintos","Viajar entre países diferentes para sus propios partidos","Partidos a gran altitud"],a:2,exp:"En el Mundial 2026, un equipo podría jugar algunos partidos en México, otros en EE.UU. y quizás en Canadá, viajando entre países durante el mismo torneo.",extra:"Esto no tiene precedente en ningún Mundial. Los equipos pueden enfrentar cambios de clima, altitud, infraestructura hotelera y zonas horarias durante el mismo torneo."},
  {t:"f",q:"El Mundial 2026 es la 23ª edición de la Copa del Mundo FIFA, contando desde el primero en 1930.",o:["Verdadero","Falso"],a:0,exp:"Verdadero. El Mundial de 2026 es la edición número 23. Desde Uruguay 1930, se celebra cada 4 años (con la excepción de la II Guerra Mundial en 1942 y 1946).",extra:"La secuencia: 1930, 1934, 1938 (pausa 1942-1946), 1950, 1954... hasta 2022 (22 ediciones). El 2026 será la 23ª. En 2030 habrá aniversario del centenario del primer Mundial."},

  // ── LOS JUGADORES ESTRELLA DEL 2026 ─────────────────────────
  {t:"m",q:"¿Cuántos años tendrá Lionel Messi durante el Mundial 2026, el cual podría ser su última participación?",o:["36 años","37 años","38-39 años","40 años"],a:2,exp:"Messi nació el 24 de junio de 1987. Durante el Mundial 2026 (junio-julio) cumplirá 39 años, lo que haría de 2026 una despedida mundialista histórica si decide participar.",extra:"Messi ya ganó todo: Copas del Mundo, Copas América, Champions League y Balones de Oro. Un posible último Mundial ante el público norteamericano sería un cierre épico."},
  {t:"m",q:"¿Cuántos años tendrá Kylian Mbappé en el Mundial 2026, esperado como favorito al Balón de Oro?",o:["24 años","27 años","29 años","31 años"],a:1,exp:"Mbappé nació el 20 de diciembre de 1998. Tendrá 27 años en el Mundial 2026, considerado el prime de un delantero. Se espera que sea el gran favorito al Balón de Oro del torneo.",extra:"Mbappé ya ganó la Champions 2022 con el Real Madrid y el Mundial 2018 con Francia. El 2026 sería su tercer Mundial y potencialmente su mejor oportunidad de ganar la Copa del Mundo."},
  {t:"m",q:"¿Quién es el atacante brasileño del Real Madrid, considerado el heredero de Ronaldo y Neymar para el Mundial 2026?",o:["Rodrygo","Raphinha","Gabriel Martinelli","Vinicius Jr."],a:3,exp:"Vinicius Jr. del Real Madrid es la gran esperanza de Brasil para el Mundial 2026. Ganó el Balón de Oro 2024 y es considerado el mejor jugador del mundo en el ciclo 2026.",extra:"Vinicius cumplirá 26 años en el Mundial 2026, su momento de mayor madurez y potencia. Brasil lleva más de 20 años sin ganar el Mundial y lo necesita para consolidar su legado."},
  {t:"m",q:"¿Qué joven español nacido en 2007 ya debutó en la selección absoluta y podría ser figura del Mundial 2026 con apenas 18 años?",o:["Gavi","Pedri","Lamine Yamal","Fermín López"],a:2,exp:"Lamine Yamal (nacido el 13 de julio de 2007) es el jugador más joven en debutar con España absoluta. Fue figura en la Eurocopa 2024 y tendrá 18 años en el Mundial 2026.",extra:"Yamal marcó un golazo en semifinales de la Eurocopa 2024. Su velocidad, técnica y carácter son los de un jugador extraordinario. Si mantiene su nivel, será la sensación del Mundial 2026."},
  {t:"m",q:"¿Qué selección europea ganó la Eurocopa 2024 poco antes del Mundial 2026, mostrando su favoritismo?",o:["Francia","Alemania","Portugal","España"],a:3,exp:"España ganó la Eurocopa 2024 en Alemania, venciendo a Inglaterra 2-1 en la final con gol de Mikel Oyarzabal. Fue su cuarta Eurocopa, un récord europeo.",extra:"España en la Eurocopa 2024 mostró una generación brillante: Lamine Yamal, Nico Williams, Pedri, Morata y Oyarzabal. Llegan al 2026 como uno de los grandes favoritos."},
  {t:"m",q:"¿Cuántos años tendrá Vinicius Jr. durante el Mundial 2026, potencialmente en el mejor momento de su carrera?",o:["23 años","25-26 años","28 años","30 años"],a:1,exp:"Vinicius Jr. nació el 12 de julio de 2000. Tendrá 25-26 años en el Mundial 2026, la edad ideal para un extremo. Es el jugador en torno al cual Brasil construirá su campaña.",extra:"Brasil no gana el Mundial desde 2002. Vinicius, junto con Rodrygo, Raphinha y otros, forman la generación más talentosa de Brasil en décadas. El 2026 es su gran oportunidad."},
  {t:"m",q:"¿Qué inglés del Real Madrid es considerado uno de los mejores centrocampistas del mundo para el ciclo del Mundial 2026?",o:["Phil Foden","Declan Rice","Harry Kane","Jude Bellingham"],a:3,exp:"Jude Bellingham, centrocampista del Real Madrid, es la mayor esperanza de Inglaterra para el Mundial 2026. Ganó la Champions 2024 con el Madrid y es el centrocampista más completo de su generación.",extra:"Bellingham tendrá 22 años en el Mundial 2026. Con el Real Madrid rindió a un nivel extraordinario, combinando goles, asistencias y liderazgo. Inglaterra espera que él les dé su primera Copa del Mundo desde 1966."},

  // ── CONTEXTO CONCACAF Y CLASIFICACIÓN ────────────────────────
  {t:"m",q:"¿Cuántos cupos directos al Mundial 2026 obtiene la confederación CONCACAF (sin contar los 3 anfitriones)?",o:["2 cupos","3 cupos directos adicionales","4 cupos directos","5 cupos"],a:1,exp:"CONCACAF tiene 3 cupos directos adicionales para el Mundial 2026 (más los 3 anfitriones automáticos), totalizando al menos 6 selecciones de la región en el torneo.",extra:"Los 3 cupos adicionales se decidieron a través de la Concacaf Nations League y las eliminatorias mundialistas. Países como Costa Rica, Jamaica, Honduras y otros compitieron por esos spots."},
  {t:"m",q:"¿Qué selección de CONCACAF que no es ni EE.UU. ni México logró clasificarse al Mundial de Qatar 2022, demostrando el crecimiento de la región?",o:["Honduras","Jamaica","El Salvador","Canadá"],a:3,exp:"Canadá se clasificó al Mundial de Qatar 2022, solo la segunda clasificación en su historia, junto a EE.UU. y México. La región tuvo tres representantes, algo no visto desde hace tiempo.",extra:"Costa Rica también clasificó como 4to equipo de CONCACAF para Qatar 2022 a través del repechaje intercontinental. En 2026, con más cupos, habrá más representación CONCACAF."},
  {t:"m",q:"¿Qué torneo de la CONCACAF sirve como fase clasificatoria inicial para determinar los cupos directos al Mundial 2026?",o:["Copa Oro","Liga de Naciones CONCACAF","Copa Centroamericana","CONCACAF Champions Cup"],a:1,exp:"La Liga de Naciones CONCACAF es el torneo clave para determinar la clasificación para el Mundial 2026. Los equipos de Liga A compiten por cupos directos o repechajes.",extra:"La Liga de Naciones fue creada para mejorar el nivel competitivo de CONCACAF. Su formato garantiza partidos de alta intensidad, reemplazando los clásicos amistosos irrelevantes."},
  {t:"m",q:"¿Cuántos cupos para el Mundial 2026 tiene la OFC (Oceanía), la confederación más pequeña de la FIFA?",o:["0 cupos directos, solo repechaje","1 cupo directo","2 cupos directos","3 cupos directos"],a:1,exp:"La OFC (Oceanía) tiene 1 cupo directo para el Mundial 2026, aumentando desde los 0.5 (repechaje obligatorio) que tenía en el formato de 32 equipos.",extra:"El cupo directo de Oceanía es un cambio histórico: antes siempre debían ir al repechaje intercontinental. Nueva Zelanda y otras selecciones de la región se benefician de esta mejora."},

  // ── IMPACTO ECONÓMICO Y SOCIAL ────────────────────────────────
  {t:"m",q:"¿Cuántos espectadores se proyecta que asistirán en total a los estadios del Mundial 2026, potencialmente un récord histórico?",o:["3 millones","4 millones","Más de 5 millones","7 millones"],a:2,exp:"Se proyectan más de 5 millones de espectadores en los estadios del Mundial 2026, lo que sería el récord histórico de asistencia en una Copa del Mundo.",extra:"El mayor número de ciudades sede (16), la capacidad de los estadios americanos y el entusiasmo por el fútbol en tres países contribuyen a estas proyecciones récord."},
  {t:"m",q:"¿Cuántos ingresos proyecta generar la FIFA con el Mundial 2026, que podría ser el evento deportivo más rentable de la historia?",o:["3 mil millones de dólares","5 mil millones de dólares","Más de 11 mil millones de dólares","20 mil millones de dólares"],a:2,exp:"La FIFA proyecta más de 11.000 millones de dólares en ingresos totales para el ciclo del Mundial 2026, un récord histórico impulsado por los derechos televisivos y el mercado americano.",extra:"El mercado norteamericano de medios es el más grande del mundo. Tener el Mundial en EE.UU., Canadá y México garantiza contratos televisivos sin precedentes en la historia del deporte."},
  {t:"f",q:"El Mundial 2026 será el primer torneo en la historia del deporte donde los equipos jugarán en tres países distintos durante el mismo torneo.",o:["Verdadero","Falso"],a:0,exp:"Verdadero. Por primera vez en la historia de un torneo deportivo de este nivel, los mismos equipos podrían enfrentar partidos en EE.UU., Canadá y México dentro del mismo torneo.",extra:"Esto nunca ocurrió antes en ningún deporte de alto nivel. La logística de viajes internacionales entre partidos de un mismo torneo es inédita y fascinante."},
  {t:"m",q:"¿Cuántos continentes del planeta estarán representados por sus selecciones en el Mundial 2026?",o:["4 continentes","5 continentes","6 continentes","Todos menos la Antártida"],a:2,exp:"Los 6 continentes habitados tendrán representación: Europa (16), Sudamérica (6+), CONCACAF (6), África (9+), Asia (8+) y Oceanía (1+). El torneo es verdaderamente global.",extra:"La distribución de 48 cupos permite que naciones de todas las regiones del mundo participen. Es el mayor número de confederaciones representadas en un solo torneo de la historia."},
  {t:"m",q:"¿Qué récord histórico del Mundial de 1994 podría romper el Mundial 2026 en términos de asistencia promedio por partido?",o:["El récord de penales","El récord de goles por partido","El récord de promedio de espectadores por partido","El récord de tarjetas amarillas"],a:2,exp:"El Mundial de USA 1994 estableció el récord de promedio de asistencia por partido (68.604 espectadores). El Mundial 2026 podría superarlo con los estadios americanos de gran capacidad.",extra:"El récord de 1994 ha durado más de 30 años. Los estadios del 2026 son más grandes y modernos que los de 1994. Con la popularidad del fútbol en crecimiento, el récord podría caer."},

  // ── TECNOLOGÍA E INNOVACIÓN EN 2026 ──────────────────────────
  {t:"m",q:"¿Qué tecnología de arbitraje, debutada en Qatar 2022, estará también en funcionamiento en el Mundial 2026?",o:["Árbitros robots","Tecnología semiautomática de offside (SAOT)","Portería con detector electromagnético","Goal-line technology con drones"],a:1,exp:"La Tecnología Semiautomática de Offside (SAOT) se debutó en Qatar 2022 y estará en el Mundial 2026. Usa 29 puntos de datos del cuerpo del jugador y cámaras especiales.",extra:"El SAOT elimina los largos tiempos de espera del VAR para decidir fuera de juego. La decisión llega en segundos con una animación 3D del cuerpo del jugador. Revolucionó el arbitraje."},
  {t:"m",q:"¿Qué innovación en el diseño del balón oficial de los Mundiales recientes permite rastrear la velocidad y posición exacta durante el partido?",o:["Un chip GPS interno","Un sensor de presión interno (Connected Ball Technology)","Un micrófono para detectar contacto","Una cámara diminuta"],a:1,exp:"La 'Connected Ball Technology' incluye un sensor en el interior del balón que registra velocidad, spin y posición exacta 500 veces por segundo, alimentando el sistema VAR y SAOT.",extra:"El balón conectado debutó en la Eurocopa 2020 y se usó en Qatar 2022. La FIFA usará tecnología similar en 2026 para mejorar aún más la precisión del arbitraje asistido."},
  {t:"m",q:"¿Cuál fue el impacto de la Copa América 2024 organizada en EE.UU. como 'prueba general' del Mundial 2026?",o:["Demostró que los estadios son demasiado pequeños","Fue un éxito operativo y sirvió para detectar mejoras logísticas antes del 2026","Generó pérdidas económicas para la CONMEBOL","Nadie fue a los partidos por el calor del verano"],a:1,exp:"La Copa América 2024 fue un éxito logístico y económico para EE.UU., con partidos muy bien organizados que sirvieron de ensayo general para los mismos estadios que usará el 2026.",extra:"Cada ciudad sede aprendió de sus errores en la Copa América 2024 para mejorar en el 2026. La seguridad, el transporte y la experiencia del fan se reforzaron con las lecciones aprendidas."},

  // ── ARGENTINA: CAMPEÓN DEFENSOR ───────────────────────────────
  {t:"m",q:"¿Argentina llega al Mundial 2026 como campeón defensor? ¿Cuándo ganó su último título?",o:["Sí, ganó en Rusia 2018","Sí, ganó en Qatar 2022","No, ganó en Brasil 2014 como subcampeón","No, no es campeón"],a:1,exp:"Argentina es el campeón defensor del Mundial 2026. Ganó Qatar 2022 venciendo a Francia por penales (3-3 en el tiempo extra, 4-2 en penalties).",extra:"Los campeones defensores tienen una historia mixta: pocos repiten el título. Solo Brasil (1958-62), Italia (1934-38) y Alemania Occ. (1972-78... ok not exactly sequential) lograron ser bicampeones consecutivos."},
  {t:"m",q:"¿Cuál es el récord de partidos invictos que acumuló Argentina antes del Mundial 2022, llegando al torneo en una racha histórica?",o:["28 partidos sin perder","33 partidos sin perder","36 partidos sin perder","42 partidos sin perder"],a:2,exp:"Argentina llegó al Mundial 2022 con 36 partidos invictos consecutivos (desde 2019), un récord histórico de selecciones. Ganaron la Copa América 2021 y luego el Mundial.",extra:"La racha de Argentina comenzó tras la derrota ante Brasil en la semifinal de la Copa América 2019. Duró hasta la primera derrota en el Mundial 2022 ante Arabia Saudita (1-2 en grupos)."},
  {t:"f",q:"Argentina perdió en la fase de grupos del Mundial de Qatar 2022 y aun así terminó ganando el torneo.",o:["Verdadero","Falso"],a:0,exp:"Verdadero. Argentina perdió ante Arabia Saudita 1-2 en la primera fecha de grupos, su mayor sorpresa del torneo. Luego ganó todos los demás partidos hasta conquistar el título.",extra:"La derrota ante Arabia Saudita fue considerada una de las mayores sorpresas en la historia del Mundial. Argentina reaccionó de manera brillante, ganando los siguientes 6 partidos de manera consecutiva."},

  // ── CURIOSIDADES DEL 2026 ─────────────────────────────────────
  {t:"m",q:"¿Qué récord histórico del goleador Miroslav Klose podría estar amenazado en el Mundial 2026?",o:["El récord de tarjetas amarillas","El récord de 16 goles como máximo goleador histórico, amenazado por Messi y Mbappé","El récord de finales jugadas","El récord de partidos consecutivos"],a:1,exp:"El récord de Miroslav Klose (16 goles en Mundiales) podría caer en 2026. Messi tiene 13 goles y Mbappé tiene 12 al inicio del 2026, ambos con una participación más por delante.",extra:"Si Messi juega el 2026 (sería su sexto Mundial), tendría 13 goles y necesita 4 más para igualar a Klose. Mbappé con 27 años estaría en su prime y también podría batir el récord."},
  {t:"m",q:"¿Qué potencia europea es la que más veces ha llegado a una final del Mundial sin ganar, siendo 'eterna finalista frustrada'?",o:["Francia","Portugal","Países Bajos","Croacia"],a:2,exp:"Países Bajos perdió 3 finales mundialistas (1974, 1978 y 2010) sin ganar ninguna. Para el 2026 buscarán finalmente obtener su primer título.",extra:"Países Bajos llegó con sus generaciones de Johan Cruyff (Total Football en 70s) y Robben/Van Persie/Sneijder (2010). En 2026 tendrán a Van Dijk, Dumfries y posiblemente nuevas figuras."},
  {t:"m",q:"¿Qué jugador inglés, de no clasificarse su selección, podría convertirse en el más nombrado de cara al 2026 por no poder participar?",o:["Bukayo Saka","Declan Rice","Harry Kane","Jude Bellingham"],a:2,exp:"Harry Kane, delantero del Bayern Munich, es el máximo goleador de la historia de la selección inglesa. Si Inglaterra clasifica al 2026, Kane podría buscar el primer Mundial de su carrera.",extra:"Kane ganó la Bota de Oro del Mundial 2018 (6 goles) pero Inglaterra perdió en semifinales. El 2026 podría ser su última chance de ganar una Copa del Mundo con casi 33 años."},
  {t:"m",q:"¿Qué es el 'SoFi Stadium' de Los Ángeles que también será sede del Mundial 2026?",o:["Un estadio universitario","El estadio más caro jamás construido, inaugurado en 2020 y hogar de los Rams y Chargers de la NFL","Un estadio cubierto de baseball","El estadio donde jugó Messi en Inter Miami"],a:1,exp:"SoFi Stadium en Inglewood (Los Ángeles) fue inaugurado en 2020 con un costo de 5.500 millones de dólares, convirtiéndolo en el estadio más caro construido en toda la historia.",extra:"Es el hogar de los LA Rams y los LA Chargers de la NFL. Su diseño futurista con pantallas gigantes y techo semitransparente lo hace uno de los estadios más espectaculares del mundo."},
  {t:"m",q:"¿Cuántas ediciones del Mundial se habrán disputado en el continente americano en total incluyendo el de 2026?",o:["7 ediciones","8 ediciones","9 ediciones","10 ediciones"],a:2,exp:"América habrá albergado 9 Mundiales: Uruguay 1930, Brasil 1950, Chile 1962, México 1970, Argentina 1978, México 1986, USA 1994, Brasil 2014 y USA/Canadá/México 2026.",extra:"El continente americano es el que más Mundiales masculinos ha organizado en total. Europa es el segundo, con Mundiales en Italia (x2), Francia (x2), Inglaterra, Alemania (x2), España y Suiza."},

  // ── ZONAS HORARIAS Y LOGÍSTICA ────────────────────────────────
  {t:"m",q:"¿Cuántas zonas horarias distintas abarcan las 16 ciudades sede del Mundial 2026 en los tres países?",o:["2 zonas horarias","3 zonas horarias","4 zonas horarias","5 zonas horarias"],a:2,exp:"Las sedes del Mundial 2026 abarcan 4 zonas horarias: Pacífico (LA, SF), Montaña (Kansas City), Central (Dallas, Houston, Chicago, Guadalajara, Monterrey) y Oriental (NY, Boston, Phila, Miami, Toronto, Vancouver, CDMX).",extra:"Esta amplitud horaria es un reto inédito en la historia del Mundial. Los horarios de los partidos deberán equilibrar las audiencias televisivas en Asia, Europa y América simultáneamente."},
  {t:"f",q:"Algunas selecciones del Mundial 2026 podrían tener que cruzar fronteras internacionales entre partidos de la fase de grupos.",o:["Verdadero","Falso"],a:0,exp:"Verdadero. Con 16 ciudades en tres países, los grupos pueden tener partidos asignados a sedes de México, EE.UU. y Canadá, obligando a los equipos a cruzar fronteras durante la fase de grupos.",extra:"Esto requiere una coordinación diplomática y logística especial: visas para múltiples países, logística de equipaje, acreditaciones, etc. Es una situación sin precedente en la historia del torneo."},
  {t:"m",q:"¿Qué ciudad de EE.UU. sin tradición de MLS pero con gran comunidad hispana es sede del Mundial 2026?",o:["Las Vegas","Chicago","Houston","Phoenix"],a:2,exp:"Houston (Texas) es sede del Mundial 2026. Tiene una de las comunidades hispanas más grandes de EE.UU. y albergará partidos en el NRG Stadium, hogar de los Texans de la NFL.",extra:"Houston no tiene equipo de MLS (el Houston Dynamo juega en un estadio más pequeño). El NRG Stadium, con más de 70.000 espectadores, fue elegido por su capacidad y la demanda local."},
  {t:"m",q:"¿Cómo se llama el estadio de Houston sede del Mundial 2026, donde juegan los Houston Texans de la NFL?",o:["Minute Maid Park","Toyota Center","NRG Stadium","Reliant Stadium"],a:2,exp:"El NRG Stadium de Houston (antes llamado Reliant Stadium) es la sede del Mundial 2026 en esa ciudad. Tiene techo retráctil y capacidad para unos 72.000 espectadores.",extra:"El NRG Stadium albergó el Super Bowl en varias ocasiones y es uno de los estadios techados más grandes de EE.UU. Houston es el centro de la comunidad latinoamericana del sur de Texas."},

  // ── OTROS DATOS CLAVE DEL TORNEO ─────────────────────────────
  {t:"m",q:"¿Cuántos árbitros en total de todo el mundo convocará la FIFA para el Mundial 2026, el torneo con más partidos de la historia?",o:["36 árbitros","45 árbitros","69 árbitros","100 árbitros"],a:2,exp:"La FIFA convocará aproximadamente 69 árbitros principales para el Mundial 2026, el mayor panel arbitral en la historia, necesario para cubrir los 104 partidos del torneo.",extra:"El cuerpo arbitral para el Mundial de Qatar 2022 fue de 36 árbitros para 64 partidos. El aumento a 104 partidos en 2026 obliga casi a duplicar el número de árbitros convocados."},
  {t:"m",q:"¿Qué selección europea, cinco veces campeona del mundo, no ha ganado el torneo desde 2006 y busca su sexto título en 2026?",o:["Francia","Italia","Alemania","España"],a:1,exp:"Italia es cinco veces campeona del mundo (1934, 1938, 1982, 2006) y no gana desde 2006. El 2026 sería su oportunidad de alcanzar el sexto título y empatar con Brasil.",extra:"Italia tuvo una crisis histórica al no clasificar para el Mundial de Rusia 2018. En Qatar 2022 quedó fuera en las eliminatorias. Su regreso al escenario mundialista es ansiosamente esperado por sus hinchas."},
  {t:"f",q:"Brasil es el país con más títulos mundiales (5), por lo que llega al 2026 como el máximo ganador histórico de la Copa del Mundo.",o:["Verdadero","Falso"],a:0,exp:"Verdadero. Brasil tiene 5 títulos (1958, 1962, 1970, 1994 y 2002), más que cualquier otro país. Alemania e Italia tienen 4 cada uno. Brasil es el máximo ganador histórico del torneo.",extra:"Brasil es el único país que ha participado en TODOS los Mundiales (23 de 23 hasta 2026). Sin embargo, lleva más de 20 años sin ganar, algo que pesa mucho sobre cada generación de 'La Canarinha'."},
  {t:"m",q:"¿Qué selección africana fue la primera en llegar a semifinales de un Mundial, logrando ese hito en Qatar 2022?",o:["Nigeria","Ghana","Senegal","Marruecos"],a:3,exp:"Marruecos fue la primera selección africana en llegar a semifinales de un Mundial, en Qatar 2022. Eliminó a España y Portugal antes de caer ante Francia.",extra:"El logro de Marruecos en Qatar 2022 inspiró a todo el continente africano. En el 2026 Marruecos buscará repetir o superar ese resultado con una nueva generación de jugadores."},
  {t:"m",q:"¿Qué jugador marroquí, estrella del Atlético de Madrid, fue fundamental en el milagro de Marruecos en Qatar 2022?",o:["Hakim Ziyech","Sofyan Amrabat","Achraf Hakimi","Youssef En-Nesyri"],a:2,exp:"Achraf Hakimi, lateral derecho del Paris Saint-Germain (y antes del Atlético), fue una de las piezas clave de Marruecos en Qatar 2022 y se proyecta como figura en el 2026.",extra:"Hakimi es hijo de inmigrantes marroquíes en España. Creció en las categorías del Real Madrid y es considerado uno de los mejores laterales del mundo, con gran incidencia ofensiva."},
  {t:"m",q:"¿Cuántos grupos habrá en la fase de grupos del Mundial 2026?",o:["8 grupos","10 grupos","12 grupos","16 grupos"],a:2,exp:"El Mundial 2026 tendrá 12 grupos de 4 equipos cada uno (48 equipos en total divididos en 12 grupos), a diferencia de los 8 grupos de 4 que había con el formato de 32 equipos.",extra:"De cada grupo avanzan los 2 primeros más los 8 mejores terceros, totalizando 32 equipos para la fase eliminatoria. Esto garantiza que muchos terceros puestos sigan en el torneo."},
  {t:"m",q:"¿Cuántos días de competición tendrá el Mundial 2026, el más extenso de la historia?",o:["32 días","38 días","39 días","45 días"],a:2,exp:"El Mundial 2026 se extenderá aproximadamente 39 días, desde el 11 de junio al 19 de julio de 2026, siendo el torneo más largo en la historia de la Copa del Mundo.",extra:"El Mundial de Qatar 2022 duró 29 días (20 noviembre - 18 diciembre). El de 2026 será 10 días más largo, necesario para acomodar los 40 partidos adicionales en el mismo formato de fase eliminatoria."},
  {t:"m",q:"¿Cuál es la fecha oficial del partido inaugural del Mundial 2026?",o:["1 de junio de 2026","11 de junio de 2026","21 de junio de 2026","1 de julio de 2026"],a:1,exp:"El partido inaugural del Mundial 2026 se jugará el 11 de junio de 2026 en el Estadio Azteca de Ciudad de México, marcando el inicio oficial del torneo.",extra:"Se eligió el Azteca como sede inaugural por su historia y simbolismo. Es el estadio más icónico de América Latina y el único en la historia en albergar tres Mundiales distintos."},
  {t:"m",q:"¿En qué fecha está programada la gran final del Mundial 2026 en el MetLife Stadium de Nueva York/Nueva Jersey?",o:["4 de julio de 2026","10 de julio de 2026","19 de julio de 2026","25 de julio de 2026"],a:2,exp:"La final del Mundial 2026 está programada para el 19 de julio de 2026 en el MetLife Stadium, ubicado en East Rutherford, Nueva Jersey, en el área metropolitana de Nueva York.",extra:"El 19 de julio cierra el torneo de 39 días que arrancó el 11 de junio. El MetLife Stadium fue elegido como sede de la final por ser el estadio de mayor capacidad y por estar en la ciudad símbolo de EE.UU."},
  {t:"m",q:"¿Qué ciudad canadiense, aparte de Toronto y Vancouver, estaba considerada pero no fue elegida como sede del Mundial 2026?",o:["Ottawa","Montréal","Calgary","Edmonton"],a:1,exp:"Montréal fue una de las ciudades canadienses consideradas para el Mundial 2026, pero finalmente no fue seleccionada. Canadá quedó con solo Toronto y Vancouver como sedes.",extra:"Montréal es la segunda ciudad más grande de Canadá y tiene tradición futbolera con el CF Montréal de la MLS. Su exclusión generó cierta controversia, ya que hubiera permitido mayor representación de la provincia de Quebec."},
  {t:"m",q:"¿Qué ciudad de México, además de Ciudad de México, Guadalajara y Monterrey, fue considerada pero no seleccionada como sede del Mundial 2026?",o:["Cancún","Puebla","Tijuana","Mérida"],a:1,exp:"Puebla fue una de las ciudades mexicanas consideradas inicialmente para el Mundial 2026, pero finalmente México quedó con tres sedes: Ciudad de México, Guadalajara y Monterrey.",extra:"México tiene 3 sedes oficiales, la misma cantidad que Canadá pero en un país más grande. Las ciudades elegidas representan los tres mercados más grandes del fútbol mexicano."},
  {t:"m",q:"¿Qué diferencia notable tiene el MetLife Stadium respecto a otros estadios del Mundial 2026 en EE.UU.?",o:["Es el único estadio cubierto","Es el único estadio sin hierba natural","Es el estadio de mayor capacidad del torneo (aproximadamente 82.500 espectadores)","Es el único estadio universitario"],a:2,exp:"El MetLife Stadium, sede de la final del Mundial 2026, tiene capacidad para aproximadamente 82.500 espectadores, siendo el de mayor capacidad entre todas las sedes del torneo.",extra:"El MetLife Stadium es el hogar de los New York Giants y los New York Jets (NFL). No tiene techo, lo que significa que la final del 2026 podría jugarse bajo condiciones climáticas variables en julio."},
  {t:"m",q:"¿Qué selección latinoamericana ganó la Copa del Mundo por primera vez en Qatar 2022 después de 36 años sin título?",o:["Uruguay","Brasil","Francia","Argentina"],a:3,exp:"Argentina ganó el Mundial de Qatar 2022 después de 36 años sin ganar (su último título fue en México 1986). Con Messi como estrella, lograron el tercer título de su historia.",extra:"En Qatar 2022, Argentina venció a Francia en una final histórica (3-3 en tiempo extra) resolviéndose en penales (4-2). Es la final más emocionante en décadas y cambió para siempre el legado de Messi."},
  {t:"f",q:"El Mundial 2026 será el último organizado con el formato de 48 equipos antes de volver al de 32 en 2030.",o:["Verdadero","Falso"],a:1,exp:"Falso. El Mundial 2030 también usará el formato de 48 equipos (ya es la política aprobada por la FIFA). El formato de 32 equipos ya quedó atrás definitivamente.",extra:"El Mundial 2030 tendrá un formato aún más especial: se repartirá entre España, Portugal y Marruecos (más partidos conmemorativos en Uruguay, Argentina y Paraguay para el centenario)."},
  {t:"m",q:"¿Cuántos países se clasificaron para el Mundial de Qatar 2022 por primera vez en su historia, demostrando el crecimiento global del fútbol?",o:["1 país (Catar, por ser sede)","2 países","3 países","5 países"],a:1,exp:"Para Qatar 2022 debutaron como primera vez en un Mundial: Catar (anfitrión) y Australia (nuevo cupo AFC tras salir de OFC). Otros como Canadá regresaron después de largas ausencias.",extra:"El aumento a 48 equipos en 2026 permitirá que aún más selecciones debuten en un Mundial, especialmente de África (9+1 cupos vs 5 anteriores) y Asia (8+1 cupos vs 4.5 anteriores)."},
  {t:"m",q:"¿Qué institución es la encargada de organizar y coordinar toda la logística del Mundial 2026 en los tres países anfitriones?",o:["CONMEBOL","La FIFA directamente","FIFA 2026 Local Organising Committee (LOC)","CONCACAF"],a:2,exp:"El Local Organising Committee (LOC) del Mundial 2026 es el organismo responsable de coordinar la organización local del torneo en los tres países, trabajando bajo la supervisión de la FIFA.",extra:"Cada país tiene representantes en el LOC. Es la primera vez que un LOC debe coordinar operaciones en tres países distintos, con culturas, idiomas y sistemas legales diferentes."},
  {t:"m",q:"¿Qué selección asiática que fue sensación en Qatar 2022 al derrotar a Argentina y a Alemania busca repetir en 2026?",o:["Japón","Corea del Sur","Australia","Arabia Saudita"],a:3,exp:"Arabia Saudita derrotó a Argentina 2-1 (en su debut) en Qatar 2022, una de las mayores sorpresas de la historia del Mundial. En 2026 buscará confirmar ese nivel inesperado.",extra:"Arabia Saudita empató con Polonia y perdió ante México, quedando eliminada. Pero la victoria sobre Argentina (en ese momento imbatida desde 2019) quedará para siempre en la historia del fútbol."},
  {t:"m",q:"¿Cuántos idiomas oficiales de los países anfitriones existen en el Mundial 2026, reflejando la diversidad cultural del torneo?",o:["1 idioma (inglés)","2 idiomas (inglés y español)","3 idiomas (inglés, español y francés)","4 idiomas"],a:2,exp:"Los tres países anfitriones tienen tres idiomas oficiales: inglés (EE.UU. y Canadá), español (México y comunidades en EE.UU.) y francés (Canadá). El torneo comunicará en los tres.",extra:"Por primera vez en la historia de la Copa del Mundo, los tres idiomas del torneo incluyen el francés por la presencia de Canadá como sede. La FIFA deberá producir toda su comunicación oficial en los tres idiomas."},
];
export default mundial2026Questions;
